INSERT INTO subtopics VALUES (2, 1, 'Elements of Control System', 'The Elements of a Control System consist of the process, the measuring element (sensor), the controller, and the final control element (actuator). This framework explains how a sensor monitors the controlled variable (CV) and transmits a signal to the controller, which acts as the decision-making heart of the loop. The controller compares the measured value to the set point (SP) to calculate the necessary adjustment for the manipulated variable (MV). The final control element, usually a pneumatic control valve, then implements this change. Students often ask how these four components interact in a feedback loop and how to distinguish between manipulated variables and disturbance variables (DV). This structural overview is essential for drawing block diagrams and is distinct from the internal mathematical modeling of the individual components.', '[0.0025183028,0.0038714001,-0.051378608,0.012182696,-0.0004778388,-0.037356544,0.007972648,0.008949301,-0.01244464,0.026729722,0.007730305,-0.023435164,0.021149024,0.021635091,-0.024497539,0.0069478597,0.02347138,-0.0024656318,0.031830158,-0.043270197,-0.026671993,0.0062212287,-0.033139694,-0.016893528,0.04082663,-0.003048842,-0.038431495,-0.0029454615,-0.014285888,0.084143795,-0.027508965,-0.041710567,-0.02979195,0.00684579,-0.03676037,-0.0012801779,0.031837426,-0.04937989,-0.039993387,0.05446313,0.014952638,-0.036797717,-0.007954168,-0.064923495,0.03133511,-0.020709489,-0.0064307977,-0.04888403,-0.022425191,-0.043436334,-0.009217602,0.012454539,0.04863515,-0.03298832,8.480124e-05,0.054190032,-0.06779655,-0.0102237845,-0.0180113,0.0136008905,-0.017397875,0.017434495,0.042354267,-0.009027131,0.020466618,0.019703899,0.013904857,-0.002229511,-0.020897346,-0.016797148,0.0319441,0.012167024,7.58392e-05,0.01649666,-0.021399057,0.033644367,0.022143818,-0.023997374,-0.04513997,0.009188402,-0.022959404,-0.008030671,0.010192904,-0.023179462,0.037091836,0.024831662,0.0