INSERT INTO subtopics VALUES (3, 1, 'Introduction to Process', 'A Process is an integrated system where materials or energy undergo transformation, such as in a continuous stirred-tank reactor (CSTR), heat exchanger, or distillation column. This subtopic defines the roles of controlled variables (CVs), which represent product quality, and manipulated variables (MVs), which are adjusted to maintain set points. Disturbance variables (DVs) are external inputs, like ambient temperature or feed composition changes, that cause deviations in the CV. Using equipment examples like U-tube heat exchangers with baffles and reflux flows, this section explains how interactions between components dictate system behavior. Students learn to classify variables and identify the mechanical mechanisms, such as agitation or reboiling, that drive the transformation. This serves as the physical foundation for modeling and is distinct from the abstract control strategies used to manage the variables.', '[-0.00803406,-0.033090428,-0.063910395,0.028377065,-0.0044290926,-0.044467293,-0.02126051,0.038207803,0.013538688,0.035620186,-0.011605437,-0.030077595,0.017091585,0.02283872,0.024978157,-0.019653855,0.011820987,0.02802823,0.03355273,-0.019916385,-0.032969967,-0.006545036,0.011947428,-0.049329117,0.045854244,0.010917386,-0.022881465,-0.027368944,-0.009686312,0.011026155,-0.021739656,0.01426383,-0.041727673,0.0028767711,-0.019145772,0.012017956,-0.0051468876,-0.043675374,-0.032427717,0.032634392,-0.0020442603,-0.0678436,0.00065696763,-0.04500752,0.046812374,-0.0029237235,-0.016250875,-0.045811903,-0.04738334,-0.046749994,-0.026526121,-0.03136378,0.07937044,-0.027195599,-0.0046353173,0.009227197,-0.06952761,0.020576326,-0.05573363,0.051294405,-0.023731023,0.032963395,0.012261032,-0.005420466,0.0052147233,0.033207145,0.00049955264,0.024527945,-0.007103886,-0.030762477,0.013802676,0.022962315,-0.017341632,0.003966772,-0.04478877,0.050989635,0.035854388,-0.04192004,-0.0064983885,0.027941588,-0.02