INSERT INTO subtopics VALUES (4, 1, 'Blending System Illustration', 'A Blending System is a benchmark process used to illustrate the interaction between mass balances and concentration control in a stirred vessel. It explains how to maintain a target output concentration of a component by adjusting a pure component inlet flow (MV) while the primary feed concentration fluctuates as a disturbance (DV). This example assumes perfect mixing and constant volume to simplify the derivation of feedback and feedforward control strategies. Students use this system to compare how feedback control corrects deviations after they occur, while feedforward control takes proactive action by measuring the disturbance. Applying combined feedforward-feedback methods or increasing tank holdup capacity are discussed as ways to damp fluctuations. This case study is a specific application of conservation laws and is distinct from thermal systems like stirred-tank heaters.', '[-0.019287407,-0.03713663,-0.04881023,0.014785885,-0.021116482,-0.07080922,0.027089491,0.017986935,-0.022111643,0.0409604,-0.027259175,-0.0007930664,-0.0016489051,0.043501053,-0.004680934,-0.0288382,0.0049935686,-0.0061272057,0.026294928,-0.023614015,-0.019182827,0.0271394,0.029921476,-0.031194244,0.03777798,0.025969395,-0.026719127,0.0005323168,-0.01631182,0.030789612,0.028256137,0.015363896,-0.041742384,-0.009607952,-0.014837286,-0.015326439,0.021783737,-0.047280665,-0.015561733,0.044483673,-0.00077040575,-0.008187432,-0.026534826,-0.04013014,0.05893935,-0.011886432,-0.007740163,-0.050610654,-0.05287996,-0.020197066,-0.010885049,0.0029220795,0.05085361,-0.006539531,0.029155264,0.045955952,-0.047329634,0.02507682,-0.032842413,0.012662917,-0.0061841193,0.04316498,0.0068449,-0.020868678,0.008294415,0.04251102,0.019207228,0.037911408,-0.02223658,-0.070342064,0.012574301,0.020861264,0.00973697,-0.00241322,-0.053582046,0.050154697,0.029269509,-0.014386395,0.008028611,-0.013890084,-0.034345675,-0.017040849,0.025548447,-0.021