INSERT INTO subtopics VALUES (5, 1, 'Feedback and Feedforward Control', 'Feedback Control is a reactive strategy that measures the controlled variable and adjusts the manipulated variable to eliminate deviations from the set point, regardless of the disturbance source. It is valued for its ability to handle unmeasured upsets but is limited by the fact that action only occurs after the process is affected. Feedforward Control is a proactive strategy that measures disturbances directly and preemptively adjusts the process before the controlled variable deviates. This requires an accurate process model and cannot account for unmeasured disturbances. Students often compare these methods to determine when to use disturbance rejection versus error-based correction. Combining both strategies creates a robust system that targets specific disturbances while maintaining overall stability. This logic is central to controller design and is distinct from the physical hardware used to implement the signals.', '[-0.029089674,-0.00522883,-0.03154425,-0.02029072,-0.015605649,-0.042852916,0.00054940855,0.065318815,0.015559269,0.049164757,-0.056087725,-0.020450339,-0.00036066608,0.000660599,-0.0041734236,0.03108568,0.021833852,-0.041491754,0.020778306,-0.068890564,0.0077468744,0.007460007,0.026189024,0.0108998725,0.03560775,0.030179001,-0.025074845,-0.009754105,-0.01212865,0.07345159,0.016064005,-0.037560944,-0.008844894,0.0068670316,-0.023564395,0.011282636,0.01440116,-0.07095976,-0.019583456,0.0040318714,-0.037181895,-0.005552029,0.024255835,-0.043826338,0.002427527,-0.030686013,0.0017698007,-0.026167499,-0.030713769,-0.039004892,-0.0029059183,-0.02527691,0.085311495,-0.04182906,0.017113095,0.039528456,-0.0067959814,-0.013590599,-0.018041352,0.048872024,-0.024901008,-0.018184906,-0.022039508,-0.02888013,0.01708536,0.024486488,-0.013081759,0.030878486,-0.0134614995,-0.07773314,0.02222604,0.021231147,-0.004646485,-0.007784853,-0.03723902,0.019448526,-0.0151989395,-0.028125482,0.020428