INSERT INTO subtopics VALUES (7, 1, 'Block Diagram', 'A Block Diagram is a visual and mathematical representation of the signal flow and functional interconnections within a control system. Each block represents a transfer function or component, showing how input signals are transformed into output signals through multiplication or summation. This tool helps students distinguish between open-loop systems, which lack a feedback path, and closed-loop systems, where the output is monitored to influence the input. Diagrams illustrate the paths for set-point changes and disturbance rejection, allowing for the simplification of complex systems into a single overall transfer function. Students use block diagrams to identify the location of sensors, controllers, and valves in the loop. This abstract mapping is a prerequisite for stability analysis and is distinct from the physical piping and instrumentation diagrams (P&ID) used in plant design.', '[-0.034244597,-0.02066032,-0.07496827,0.007599261,-0.015385614,-0.03975257,0.014631133,0.002926744,0.014286553,0.031454973,-0.02612121,-0.014227918,0.014122249,0.023196744,-0.006724613,0.00084381027,0.005480594,0.007745772,0.0404512,0.0022868793,-0.005322748,-0.011971995,0.0237128,0.0060432074,0.009992107,0.0178565,0.0064570475,0.009743718,-0.024148794,0.07278022,0.025551219,-0.020659627,-0.016417313,0.023973119,-0.032026727,0.009724746,-0.013183567,-0.027757507,-0.02386643,0.025602046,-0.014417523,-0.012064146,0.0044901343,-0.046504326,0.033872392,-0.0046200515,-0.016926963,-0.0299578,-0.048868325,-0.047058206,0.008673238,-0.012043239,0.042676423,-0.03610482,0.01555253,0.015533419,-0.03782975,-0.020569604,-0.060497597,0.0041799485,-0.0137983225,0.052864954,0.007650182,-0.028986122,0.008011025,0.022783037,-0.013214704,0.007968106,-0.018348034,0.0063896216,0.010381787,-0.0003492725,-0.027093925,0.014587435,-0.027640846,0.036704864,0.0057045543,-0.039993964,-0.024041466,0.05652078,-0.03133812,-0.019598186,-0.0009897631,-0.021675417,