INSERT INTO subtopics VALUES (9, 2, 'Process Models', 'A Process Model is a mathematical representation, typically involving ordinary differential equations (ODEs), that captures the essential dynamic behavior of a system for the purposes of design and control. This subtopic explains how models balance accuracy and complexity to simplify transient behavior without losing critical features. Models are used to optimize operating conditions, evaluate control strategies, and train plant personnel in a safe, simulated environment. Students learn to identify controlled and manipulated variables within the model structure to predict how a system will respond to inputs. Dynamic models are essential for understanding time-dependent changes, whereas static models only describe steady-state conditions. This theoretical foundation is distinct from the physical equipment it represents and is the first step in creating transfer functions.', '[-0.04250896,-0.019243982,-0.058316287,0.0059076305,-0.00981548,-0.05471141,-0.003839982,0.036680743,0.034409244,0.027979089,-0.06964865,-0.03524705,0.024796395,0.013837739,0.01199518,0.036482885,0.00909601,0.019240672,0.045279354,-0.01799603,0.01389486,-0.016144546,0.075646006,-0.013630719,-0.014307099,0.01171907,-0.0003568914,-0.02514834,-0.00058033515,0.012692155,-7.634493e-05,0.009389586,-0.031380598,0.008284478,-0.044272725,0.03772629,0.006733669,-0.04519658,-0.029202286,0.02408536,0.0030188716,-0.064790405,0.015996456,-0.037147798,0.022605632,-0.0110993525,-0.033144053,-0.034660675,-0.050753925,-0.049915485,-0.006616307,-0.036854245,0.053938836,-0.056227017,0.0045450306,0.030340621,-0.062692985,0.0017091205,-0.07503241,0.04890442,-0.05585404,0.03440481,0.027334569,-0.031025486,-0.0015293646,-0.0044494024,-0.038423818,0.01135884,-0.010323338,-0.048091736,0.01420308,0.008577696,-0.03421505,-0.0055188243,-0.04250834,0.030673485,-0.025336208,-0.013813423,-0.0507075,0.065681584,-0.037414238,-0.0185101,-0.0029302093,-0.019271292,0.015957747,-