INSERT INTO subtopics VALUES (10, 2, 'Modelling Approaches', 'Modelling Approaches categorize the methods used to build process representations: Theoretical, Empirical, and Semi-empirical models. Theoretical models (First-principles) are derived from conservation laws, transport phenomena, and kinetics, offering high insight and extrapolation but requiring long development times. Empirical models (Black-box) are built using experimental data and regression, making them fast to develop but limited to the range of the original data. Semi-empirical models (Grey-box) combine physical intuition with data-driven parameter fitting to achieve a balance of accuracy and efficiency. Students learn to choose an approach based on the available data and the required level of detail for the control task. This decision-making process is distinct from the actual derivation of the equations and focuses on the trade-offs between development effort and model reliability.', '[-0.043079764,-0.04149005,0.007280789,0.02444415,-0.012799386,-0.04926684,-0.00910793,0.062248286,0.0039652586,0.05251789,-0.044319205,-0.028550852,-0.00020122767,0.0149643775,0.019659083,0.04031647,0.002787218,0.023339115,0.013465915,-0.046393156,0.039505135,-0.024223872,0.029756166,-0.0014815956,0.008137127,-0.010967626,-0.009007919,-0.024755696,0.0073233647,0.044263422,0.009529871,-0.0032070507,-0.00457023,-0.0059805615,-0.0010436892,0.012729394,0.014308539,-0.030917197,-0.024827069,0.008619571,-0.0007928594,-0.056510713,0.037592363,-0.06758235,0.033624344,-0.009844797,-0.023779897,-0.044013698,-0.02401825,-0.041757148,0.026872737,0.017363876,0.0054003084,-0.042977944,0.0029044438,0.063496664,-0.03193068,0.004851811,-0.062334687,0.009487234,-0.07600479,0.019982442,0.022569224,0.010462177,0.006705348,0.0030679712,-0.018218327,0.011021416,-0.0086221285,-0.070445195,-0.0096823685,-0.037586834,-0.049203306,-0.012127092,-0.025102913,0.0070226807,-0.024409609,0.0061795064,-0.024433758,0.03854653,-0.035575207,-0.0087887