INSERT INTO subtopics VALUES (11, 2, 'Conservation Laws', 'Conservation Laws provide the fundamental ''First Principles'' for process modeling, specifically the Conservation of Mass, Conservation of Component i, and Conservation of Energy. These laws state that the rate of accumulation within a system equals the rate of mass or energy in minus the rate out plus the rate of generation. Total Energy is computed by summing internal, kinetic, and potential energy, though internal energy usually dominates in chemical processes. These laws are applied to derive unsteady-state balances for units like reactors and tanks. Students use mass and component balances to track concentration changes and energy balances to model temperature fluctuations. Accounting for every species and thermal unit is essential for ensuring model closure. This subtopic is the mathematical starting point for all theoretical models and is distinct from empirical data fitting.', '[0.0026354266,0.014318478,-0.031949293,0.020442355,-0.036126424,-0.10999578,-0.0020426658,0.02611751,-0.020177687,0.018799165,-0.049090013,-0.06436653,-0.022920959,0.0076531805,-0.016122898,0.04545459,-0.015606152,0.045676984,-0.017846208,-0.038480632,0.02501658,0.010990522,0.044027813,-0.032201756,0.018624987,0.019881656,-0.027691064,-0.040039204,-0.0024876276,0.0394043,0.01572445,0.013805527,-0.034327593,-0.032872766,-0.010414034,0.01810801,0.01195299,-0.028844677,-0.02752829,0.015837828,-0.0043661916,-0.05396124,0.007927521,-0.048664656,0.030688629,-0.00930624,-0.02720863,-0.055591837,-0.03872454,-0.04425126,-0.005082669,0.023596697,0.03764333,-0.041382175,0.0067693978,0.055854995,-0.066367716,0.0060631344,-0.06662802,0.008849768,-0.042098124,0.024702942,-0.015488774,-0.0048899087,0.029254895,-0.005494799,0.0098315915,-0.014826529,-0.006960826,-0.03594398,0.00023552668,0.014769526,-0.061843343,-0.03333678,-0.049524844,0.010743657,-0.014743996,0.0016829179,-0.033781942,-0.017705258,-0.025071656,-0.03264963,0.02057192,-0.013