INSERT INTO subtopics VALUES (12, 2, 'Development of Dynamic Models', 'The Development of Dynamic Models involves applying unsteady-state balances to physical systems like blending tanks, stirred-tank heaters, and liquid storage units. This process explains how to derive differential equations that describe volume, concentration, and temperature changes over time. In liquid storage, students model how height (h) varies based on inlet flow and outlet resistance, often involving nonlinear square-root relationships for turbulent flow. In heating systems, energy balances are coupled with mass balances to track heat input (Q) and holdup. This subtopic emphasizes making valid assumptions, such as perfect mixing and constant density, to keep models tractable. Students learn to handle nonlinearities by identifying where variables interact multiplicatively. This procedural knowledge is distinct from the abstract study of conservation laws and focuses on the practical derivation for real engineering equipment.', '[-0.0058174334,-0.030653428,-0.027567977,0.01874679,-0.032347575,-0.062364142,-0.0028539598,0.009472923,-0.013895543,0.0115841,-0.0072152615,-0.013245554,-0.034349136,0.025912156,-0.0076352423,-0.0011800259,-0.020071935,0.02876503,0.00012276406,-0.048974946,0.003200423,-0.029305996,0.045917064,-0.025503509,0.034086794,0.04148147,-0.0036374102,0.0035168305,-0.009037117,0.036431674,0.031327315,0.030176379,-0.053468566,-0.026179913,-0.030855205,0.00096405146,-0.02528697,-0.0293773,-0.029707076,0.058787454,0.011172169,-0.013332305,0.0053796284,-0.031366087,0.033090536,-0.019985747,-0.059402864,-0.024876136,-0.050842654,-0.03658108,0.0140061425,-0.009611776,0.06329807,-0.022121977,0.019550528,0.0030881793,-0.06969833,-0.01308311,-0.06393747,0.038762607,-0.05291817,0.040642552,-0.005922734,-0.0027916234,-0.015226974,0.028903166,0.014144674,0.029911332,-0.02916963,-0.08029045,-0.002080524,0.020039067,-0.028426971,-0.014853573,-0.06266843,0.02171544,0.005793769,-0.0040949383