INSERT INTO subtopics VALUES (14, 3, 'Laplace Transform of Typical Functions', 'The Laplace Transform of Typical Functions provides the s-domain representations for standard process inputs, including Step, Ramp, Impulse, and Sinusoidal functions. A Step Input ($1/s$) models sudden, sustained changes, while the Heaviside function represents delayed activation. Exponential functions ($1/(s+a)$) represent growth or decay, and Sinusoidal functions ($s/(s^2+w^2)$) model oscillatory disturbances or cyclic noise. These standard forms allow students to quickly map time-domain forcing functions into the s-domain for multiplication with transfer functions. Understanding these transforms is vital for predicting how a process will respond to common industrial upsets like feed changes or electrical interference. This subtopic is a prerequisite for using Laplace tables and is distinct from the study of general transform properties.', '[-0.0324933,0.016901327,-0.042445842,0.02836599,-0.0026401777,-0.0337035,0.01258552,0.031381495,0.016430378,0.021061605,-0.0018462071,0.036027893,0.014203499,0.0075364364,0.05882332,0.023733433,0.022582455,0.020711634,0.024074178,-0.014120808,-0.013366003,0.04828618,-0.002664689,0.012349708,-0.04992218,0.03879994,-0.004419424,-0.029727181,0.012328207,0.01510968,0.0001971657,-0.007602791,-0.042613998,-0.029186364,-0.057458382,0.026205136,0.00090087025,-0.008276872,-0.054251708,-0.0007235644,-0.018687492,-0.021901889,0.055065215,-0.022561885,0.041304056,0.0040861964,-0.026613165,-0.050809644,-0.011887265,-0.030044246,0.022289112,-0.046248604,0.021048604,-0.033924017,0.028688163,-0.013287662,-0.031462137,-0.04015404,-0.08263576,0.017410982,-0.04501818,0.05939211,-0.04073439,-0.0078377295,0.0072844285,-0.0047007124,0.033253424,0.022107495,-0.0007283161,-0.011510081,-0.0004498072,0.029482216,-0.06532393,0.035074573,-0.053844288,0.07329534,-0.016115494,-0.02190703,0.011255074,0.06839438,-0.011141591,-0.022122035,-0.014696631,0.009808294,-0.024983741,0.015