INSERT INTO subtopics VALUES (18, 4, 'Properties of Transfer Function Models', 'Properties of Transfer Function Models include the Steady-State Gain (K), Time Constant (tau), and Order (n). The Steady-State Gain represents the final change in output divided by the change in input once the process settles, while the Time Constant indicates the speed of the response (the ''sluggishness'' of the system). The Order is determined by the highest power of s in the denominator polynomial and reflects the dynamic complexity. Physical Realizability requires that the denominator order is greater than or equal to the numerator order. Transfer functions in series are combined via multiplication, while parallel paths are added. Students use these properties to characterize systems as first-order, second-order, or integrating. These metrics are distinct from the specific coefficients of an ODE and provide a standardized way to compare different process behaviors.', '[-0.04516877,-0.01650083,-0.06929094,0.0056206537,-0.01462665,-0.000865766,0.002041259,0.03165044,0.01686892,0.047980364,-0.0076817856,-0.010002565,0.0058907825,0.02368343,0.04275706,0.041949023,-0.0062152944,0.016802972,-0.011256465,-0.0012336577,0.006458074,0.023158709,0.03243441,0.028129777,-0.0049408893,0.041513298,-0.030448394,-0.037276912,0.0049316916,0.08472866,0.020898126,0.027766785,-0.004569069,-0.027495753,-0.06346192,0.0347758,0.016364913,-0.04205823,-0.039319906,0.054639783,-0.024363827,-0.013721555,0.02617213,-0.066846706,0.06372594,-0.016128996,-0.003433102,-0.034836717,-0.038863603,-0.030607563,-0.00033406634,-0.036905877,0.049469177,-0.032860033,0.025376707,-0.0028794273,-0.076522164,-0.028053334,-0.048628647,-0.0030292347,-0.057300925,0.08747909,-0.027834909,-0.012134179,0.009080071,-0.0077258204,0.0119683,0.0031638844,-0.008913869,-0.022973431,0.029834442,0.048354927,-0.045476418,0.011621031,-0.043574736,0.025045078,-0.03662536,0.0053648255,-0.003032379,0.034500685,-0.028655084,0.020370208,0.03441669