INSERT INTO subtopics VALUES (19, 4, 'Linearization of Nonlinear Models', 'Linearization of Nonlinear Models addresses how to approximate chemical processes governed by nonlinear differential equations with linear models near a specific operating point. This is achieved using a first-order Taylor series expansion, where higher-order terms are neglected for small deviations. The resulting linear relationship is exact at the steady-state expansion point and allows for the use of transfer functions. Linearization involves calculating partial derivatives evaluated at the reference condition to derive linearized resistance or gain. Students apply this to systems like liquid tanks where outflow is proportional to the square root of height. This approximation is valid only in the vicinity of the steady state and is the standard method for designing controllers for inherently nonlinear plants. It is distinct from global nonlinear analysis which requires numerical simulation.', '[-0.05658513,0.0073069003,-0.031152232,-0.0012338873,-0.023623828,-0.01029166,0.0058390046,0.038697664,0.0035163497,0.05024987,-0.047909558,-0.023614557,-0.004937803,0.031848736,-0.021450935,0.0037298033,0.0044924314,0.021841094,0.037198607,-0.032850567,-0.03712312,-0.037597325,-0.0069497856,0.0016268955,-0.020943647,0.00023024387,-0.043735944,-0.0149815045,0.009136048,0.035441134,0.056355134,-0.0025645643,-0.028763805,-0.038198337,-0.014627765,0.054533426,0.027996236,-0.03947423,-0.022208262,0.031217404,0.00430444,0.005496374,0.0076736268,-0.005524655,0.025418827,-0.008160116,-0.0324911,-0.042312708,-0.029725341,-0.054293767,-0.01638179,-0.022546362,0.042808365,-0.025145123,-0.0095611755,0.011572593,-0.04206525,-0.013262085,-0.062279284,0.030752352,-0.08260076,0.013829845,-0.021707116,-0.02048553,0.007933458,-0.0077536264,0.0052310475,0.042307768,-0.00633022,-0.06615703,0.006954275,0.03344589,-0.030902471,-0.014677437,-0.056177046,0.01984628,0.01851467,-0.033481043,0.03221582,-0.0002814504,-0.028056