INSERT INTO subtopics VALUES (21, 5, 'Response of First Order Processes', 'The Response of First Order Processes characterizes systems defined by a single time constant (tau) and process gain (K). In response to a Step Input, the output follows a gradual exponential curve, reaching 63.2% of its final value at t = tau and settling after 5 tau. A Ramp Input results in a constant lag between input and output, while a Sinusoidal Input produces an amplitude-attenuated and phase-shifted oscillation. Key parameters include the speed of response (determined by tau) and the magnitude of the final change (determined by K). Students apply these models to single-tank systems and simple thermal processes to predict how fast a system recovers from upsets. This first-order behavior is the simplest form of dynamic response and is distinct from the oscillating or ''overshooting'' behavior of second-order systems.', '[-0.03594319,-0.0016178726,-0.03519123,-0.0071593765,-0.005455534,-0.06165736,0.0021228273,0.03646871,0.0042323316,0.043329842,-0.0029262917,-0.030680006,0.0069888146,-0.00836428,0.011152442,0.06039837,-0.009335507,0.020313632,-0.0052342494,-0.0061249165,-0.020812586,0.061253775,0.025273874,0.0026114506,-0.021987265,0.024289086,-0.035068586,-0.037383538,-0.014769107,0.06805279,0.028358143,0.028856024,-0.01608301,-0.034883954,-0.030326279,0.04005434,0.0032710303,-0.057167064,-0.048176,0.04632347,-0.006314967,-0.02988753,0.045596153,-0.02214898,0.054902226,-0.00011807061,-0.032662056,-0.045917947,-0.04063762,-0.050133795,0.0153758265,-0.04371648,0.018822819,-0.02817884,0.0005115005,0.04493949,-0.053889316,0.00413926,-0.021344816,0.026568122,-0.027034283,0.07544978,0.019966137,-0.03469736,-0.033760637,0.008309119,0.019473497,0.022767467,-0.009739105,-0.0075944345,0.010323853,0.021852737,-0.017813649,-0.0007565073,-0.040159225,0.042603184,0.042703297,-0.013264453,0.009921624,0.012847724,-0.021994222,-0.0066809785,-0.0007245474,-0.0328761,0.012574552,0.04119486,-0.005334205,0