INSERT INTO subtopics VALUES (23, 5, 'Response of Second Order Processes', 'The Response of Second Order Processes describes systems governed by second-order ODEs or two first-order processes in series, defined by the Damping Ratio (zeta) and Natural Frequency. The damping ratio determines if a system is Overdamped (zeta > 1, slow and non-oscillatory), Critically Damped (zeta = 1, fastest non-oscillatory), or Underdamped (zeta < 1, fast with oscillations). Underdamped step responses are characterized by Overshoot, Decay Ratio, Rise Time, Settling Time, and Period of Oscillation. Students learn how connecting tanks in series or adding controllers creates these complex dynamics. This subtopic explains why some processes ''ring'' or oscillate before stabilizing. It is distinct from first-order responses as it can exhibit unstable growth or sustained oscillations if not properly damped.', '[-0.067000516,-0.03411615,-0.024732482,0.0077162995,-0.011249957,-0.056122717,0.0046391506,0.013834643,-0.008068771,0.042456485,-0.02568876,-0.051297512,-0.009378708,-0.003953241,0.02509356,0.020917796,-0.016276777,0.008797696,-0.023802698,-0.014162731,-0.013943476,-0.0032258222,0.011467142,-0.0110048,-0.020225706,0.0033982298,-0.034524675,-0.034996435,-0.004523372,0.027670907,0.011079438,0.0138947675,-0.0030716623,-0.044900864,-0.01693088,-0.007377298,0.0051998766,-0.046520207,-0.04030992,0.014103412,-0.01987109,0.0050908383,0.027044991,-0.01891793,0.08458051,0.0071555907,-0.026259128,-0.04825102,-0.031062076,-0.045619283,-0.016232153,-0.02288685,0.070544854,-0.014314718,-0.012966778,0.061050367,-0.043339245,-0.018961309,-0.06015409,0.0374613,0.0059663015,0.030586027,0.011294723,0.0043297666,0.017451769,0.036386043,0.010765075,0.011405516,-0.033107165,-0.001422805,0.03414146,0.03154949,-0.0020478654,-0.010904035,-0.021440823,0.060731653,0.004429319,-0.008312209,-0.015908722,0.038916763,-0.013241006,-0.0046499944,0.024988212,0.003834352,-0.012869453,0.030968916,-0.0036627266,0.0127408