INSERT INTO subtopics VALUES (25, 6, 'Poles and Zeros and Their Effects', 'Poles and Zeros and Their Effects describe how the roots of the transfer function''s denominator (Poles) and numerator (Zeros) dictate dynamic behavior. Poles determine stability: if all poles reside in the Left Half Plane (LHP), the system is stable. If any pole is in the Right Half Plane (RHP), the system is unstable. Poles on the imaginary axis indicate marginal stability or sustained oscillations. Zeros affect the transient response shape (e.g., overshoot or speed) but do not change the stability mode. Complex poles lead to oscillatory behavior, while repeated real poles slow the response. Students map these roots on a complex s-plane to predict the system''s characteristic response. This mapping is distinct from time-domain simulation and provides a direct visual method for assessing system robustness.', '[-0.053747173,-0.03504865,-0.058748156,0.047006816,-0.008797868,-0.07220108,0.012343632,0.039700765,0.0005986803,-0.0045027784,-0.053775012,0.009118899,-0.01382988,0.012962039,0.018511398,0.009875022,-0.0038576296,-0.021958135,-0.0062834476,-0.019032083,-0.02145781,-0.031906843,-0.044414397,-0.0072358856,0.011770797,0.006306812,-0.035005525,0.005641912,-0.027814886,0.09718752,-0.004255086,0.018680777,-0.0047638104,0.004930085,-0.02629954,0.0096206,-0.00052693486,-0.04528124,-0.03231051,0.0075254943,-0.02561031,-0.029452644,0.012059547,-0.024705127,0.020884398,-0.006099786,-0.033315983,-0.045255408,-0.023870524,-0.033934146,-0.009493341,-0.03413353,0.04822162,-0.016801076,-0.013676544,0.05920902,-0.037806083,-0.027600849,-0.06492415,0.022895679,-0.015922032,0.055346817,-0.04597542,-0.030701952,-0.02900861,0.042857416,-0.013505247,0.022153592,-0.024925895,-0.051027782,0.0020617167,0.018680396,-0.002102614,0.00389637,-0.031086193,0.030068744,-0.016090255,-0.03416036,-0.01449574,-0.00028267587,-0.022786131,-0.014049023,0.012607937,0.0012522016,0.025947824,0.032730747,0.040866077,0.026476873