INSERT INTO subtopics VALUES (26, 6, 'Numerator Dynamics', 'Numerator Dynamics focuses on the impact of Zeros (numerator roots) on the transient response of a transfer function. While poles determine stability, zeros alter the magnitude of response modes, often causing Overshoot or Inverse Response. An Inverse Response occurs when an unstable zero exists in the Right Half Plane (RHP), causing the output to initially move in the opposite direction of its final steady state. This is common in systems with parallel paths with opposing gains, such as drum boiler levels or distillation columns. Students learn to identify how the numerator time constant (tau_a) relates to the denominator time constants to predict these ''non-minimum phase'' behaviors. This analysis is distinct from pole analysis as it focuses purely on the ''initial'' path the output takes before the poles dominate the final settling.', '[-0.05943986,-0.022399196,-0.044221696,0.048501182,-0.028050208,-0.039032847,-0.012062249,0.060711034,0.0066560907,0.042789448,-0.050579436,-0.009384678,-0.0066356338,-0.013952932,0.0024432305,-0.02457188,0.0016902331,0.0020355298,0.0070416545,0.009222965,-0.0029707048,0.01424037,-0.038576994,-0.023948155,-0.003948909,0.0100888405,-0.04290211,-0.020081328,-0.0022861136,0.075312056,0.0052671884,-0.0006107096,0.0042451173,-0.023841381,-0.025863023,0.047051948,0.005414993,-0.053872596,-0.027115377,0.0127956355,0.0039643333,0.0021425385,-0.005067143,-0.049790617,0.058005165,0.009804446,-0.025183143,-0.047649484,-0.024446605,-0.049589667,0.0093576405,-0.017368296,0.047718227,-0.0072568455,-0.014513025,0.043730125,-0.010206985,-0.023423366,-0.054036826,0.026353678,-0.005678015,0.031404905,0.0024020236,-0.02666236,-0.03640694,0.044656664,-0.007719605,0.020312015,-0.016394364,-0.02108337,0.014561329,0.034730505,-0.015837407,0.010577713,-0.053819582,0.025552532,0.0058291615,-0.031598482,-0.020349804,-0.021403953,-0.01906133,-0.019233305,-0.020683622,-0.014759212,0.014258113,0.0400