INSERT INTO subtopics VALUES (27, 6, 'Processes with Time Delays', 'Processes with Time Delays (Dead Time or Transport Lag) describe the finite period between an input change and the first observable output response, typically caused by fluid flow in pipes. Time delay is represented by the term e^(-theta s) in the s-domain, which is a non-rational function. Because dead time cannot be expressed as simple poles or zeros, approximations like the Taylor Series or Pade Approximation are used to create rational transfer functions for controller design. Delays do not affect the steady-state gain but significantly limit the maximum allowable controller gain and reduce system stability. Students often compare s-shifting to t-shifting to understand how transport lag differs from frequency shifting. This concept is critical for modeling long pipelines and is distinct from the ''sluggishness'' caused by large time constants.', '[-0.061302472,-0.04279174,-0.023667116,0.02465105,-0.013337804,-0.009799199,-0.025001982,0.056181844,-0.025394963,0.047903325,0.005468302,0.00026791202,0.0049102344,0.013232529,0.00948078,-0.009222043,0.016303495,0.026924841,-0.009408819,-3.1567874e-05,0.026542628,-0.0065413867,-0.020026559,-0.0066598784,0.018237144,-0.0077211238,-0.031976957,-0.008821718,0.05532653,0.03971632,0.026411235,0.03248663,-0.0064408733,-0.016882619,-0.050737053,0.000174937,0.0013741938,-0.022642191,-0.031056235,0.005895415,-0.03914482,-0.005783745,0.039082035,-0.049804427,0.06519848,-0.018011943,-0.037647497,-0.03524273,-0.02975754,-0.0371244,0.014342278,-0.04402564,0.06528773,-0.026455509,-0.0044232314,0.044442106,-0.053571884,-0.03891549,-0.059888504,0.046900474,-0.045580354,0.031434536,0.016206566,-0.062753014,0.051593434,0.017855309,0.017247,0.025366182,-0.01769026,-0.024902796,0.03522394,0.02492669,-0.012056441,-0.00033597802,-0.020597113,0.039132673,-0.0077832243,-0.011030498,-0.0029783119,0.023738958,0.008114432,-0.014211458,0.017978158,-0.00689653,-0.01088035,0.018812