INSERT INTO document_chunks VALUES (1, 1, 'This chunk introduces the importance of studying Process Control. Process control is studied due to performance requirements such as stronger competition, tougher regulations, rapidly changing economic conditions, and complex processes. Due to increased emphasis on safe, efficient and high quality process, process control has become increasingly important. Computer-based process control systems are also being increasingly used.', '[-0.035166565,0.031985268,-0.033454023,0.006765035,-0.030015742,-0.008404283,-0.023959536,0.07630404,0.022337448,0.013790535,-0.048054736,-0.03057615,-0.01700573,0.006564654,-0.003077511,0.006628063,0.011373671,0.0035148074,0.015756322,-0.021562954,0.00527564,0.002389067,0.026592635,-0.009998098,-0.030155847,0.009864279,0.0141403945,0.008922808,-0.011932176,0.021937722,0.013161006,-0.0040867687,0.03179743,-0.01995727,-0.029034007,-0.005024398,0.012599276,-0.069778994,-0.01819782,0.003293942,0.013099684,-0.026226154,0.021779424,-0.017654741,0.0027279046,-0.0035324448,-0.02116127,-0.033836108,-0.08752889,-0.018705368,0.0034954853,-0.018134993,0.052545864,-0.042393368,-0.010082038,0.0168473,-0.04226025,0.0071066455,-0.013453597,0.017751256,-0.039615255,0.014362113,0.019726316,-0.043304402,0.035528325,0.038824275,-0.008295399,0.008510757,0.012232645,-0.047324188,0.022197943,0.024629764,0.0036745158,-0.0005314508,-0.0447689,0.024092257,-0.037197605,-0.017446836,0.032745082,0.027882287,-0.03417861,-0.025923911,0.02922491,-0.014672786,0.00044375416,0.016768988,-0.018763991,-0.0011875248,0.0013307937,0.019017903,-0.018086288,0.0009377171,0.010508879,-0.00068402785,-0.0012208422,-0.019446693,-0.015309093,0.0011622646,0.004796137,-0.016456774,0.0067667365,0.05013703,0.0012259373,-0.0018670377,0.011281388,-0.011526452,0.03791722,0.04798812,0.031973884,-0.012970191,0.04713701,0.043965377,0.022368696,-0.0048685786,0.016438842,-0.04327956,0.010611066,0.0057615046,0.041839927,0.01601933,-0.023269514,0.042261284,