INSERT INTO document_chunks VALUES (4, 2, 'This chunk identifies the four essential elements that comprise any control system, using the washing hands analogy to illustrate how these elements work together in a practical feedback control loop. The essential elements of a control system are the process, measuring element (sensor), controller, and final control element. A simple everyday analogy is the process of washing hands, where the brain acts as the controller, adjusting the water flow rates from the tap or control valve (final control element) based on temperature feedback from the hands (sensor) to maintain comfortable water temperature.', '[0.012266494,0.03328324,-0.062405366,0.02093453,-0.02336451,-0.06896444,0.034019012,0.004179731,-0.011809545,0.038214643,-0.015278623,-0.018608117,0.0034391661,-0.016603945,0.018991135,0.027514715,0.02529736,-0.0037555366,0.0049220216,-0.049361143,-0.007992825,0.014437866,0.017007058,-0.0036684405,0.0016230806,0.00639121,-0.04335303,-0.0048970953,-0.01756387,0.062176555,-0.021631526,-0.028564751,-0.022850655,0.0030183177,-0.06035907,0.006191421,0.0048535126,-0.056819957,-0.030381372,0.032580707,-0.011853767,-0.047929652,0.0021987099,-0.044568047,0.015732288,-0.021880021,-0.020161249,-0.042667504,-0.040171593,-0.021332145,0.014369385,0.023965374,0.046145495,-0.030347858,-0.017443497,0.07389558,-0.08380589,-0.0055851922,-0.035010505,0.039510835,-0.016619744,-0.0011471173,0.022321448,-0.020419758,0.037790436,0.011189599,0.019910926,0.012270832,-0.016598133,-0.022918288,-0.0037840947,0.007824519,-0.020944806,0.0040621064,-0.027252467,0.028400755,-0.0055465125,-0.016270915,-0.0067688767,0.07432953,-0.013841272,0.009150184,0.010991448,0.0007030822,0.00671534,0.030543264,0.0073151574,0.041245095,-0.010886139,-0.011316431,-0.04020513,0.004686982,0.032834116,-0.015874358,-0.02740621,0.019354023,0.0028919557,-0.032441605,0.015250237,0.007791596,-0.027258959,-7.651219e-05,-0.005178532,-0.039975025,0.0644324,-0.0032715658,0.078737035,0