INSERT INTO document_chunks VALUES (5, 3, 'This chunk introduces the concept of a process in chemical engineering using common industrial equipment examples such as U-tube heat exchangers, continuous stirred tank reactors (CSTRs) and fractionating columns. The first example is a shell and tube heat exchanger which illustrates how heat is transferred between two fluid streams. The second example is a continuous stirred-tank reactors (CSTRs) which demonstrates how chemical reactions take place with continuous mixing. The third example is a fractionating column which shows that the components are separated based on differences in volatility. These processes are the physical systems that must be controlled to maintain desired operating conditions and product quality.', '[-0.041428532,-0.015710142,-0.030623484,0.02504244,0.01302906,-0.043116886,-0.021924298,0.0333504,-0.03843084,0.03921078,0.009672144,-0.011943176,-0.0033315562,0.013651253,0.004511033,-0.019456418,0.013413558,0.014496541,0.008144102,-0.025698772,-0.016456326,0.0020430537,0.007920519,-0.023138449,0.009993534,0.03811464,-0.0074759894,-0.00877873,-0.0010356733,0.02124731,0.029290935,0.02818062,-0.03472167,-0.012902068,-0.015053031,-0.009162045,0.010050203,-0.025565807,-0.032009486,0.03977739,-0.0046383925,-0.038522635,0.033546094,-0.039991595,0.024031851,-0.017374411,-0.024324385,-0.049297787,-0.021790056,-0.03489917,-0.02561449,0.0018583202,0.03485505,-0.033616982,-0.013045326,-0.01411463,-0.10967418,0.00041216615,-0.08379836,0.051773574,-0.04037248,0.029371534,-0.005804477,-0.0047637746,0.02869565,0.02979821,-0.007465212,0.010196053,-0.006814557,-0.041525867,-0.019972982,0.0245569,-0.011857644,-0.02992785,-0.059489273,0.041935198,0.036967695,-0.041874897,0.029068064,-0.0034768113,-0.017165199,-0.021509893,0.027685735,-0.017811181,0.017161671,0.021240635,0.008186322,0.02891308,0.024388537,-0.07126192,-0.013397098,0.014075705,-0.031828288,-0.0016033876,-0.01854967,-0.010565205,-0.017476665,0.027838303,0.013