INSERT INTO document_chunks VALUES (6, 3, 'This chunk defines the three fundamental process variables (controlled, manipulated, and disturbance variables) for analyzing and designing process control systems. Process variables are classified into three categories. Controlled variables (CVs), also called output variables, are the variables that quantify the performance or quality of the final product, and the desired value of a controlled variable is referred to as its set point. Manipulated variables (MVs) are input variables that are adjusted dynamically to keep the controlled variables at their set points. Disturbance variables (DVs), also called load variables, represent input variables that can cause the controlled variables to deviate from their respective set points.', '[-0.031789195,-0.0065421727,-0.06333011,0.040149774,-0.0006824728,-0.008120443,-0.015617986,0.029691666,-0.0057890974,0.0517157,-0.047978513,-0.035157986,0.020661041,-0.004934405,0.0194431,0.0013483171,0.0019177027,-0.02641518,0.011026647,-0.04191639,-0.008965931,0.01078967,-0.04127586,-0.013268865,0.023029992,0.004962738,-0.021689277,-0.022599354,0.00031859748,0.040469255,-0.018286891,-0.0338337,-0.031700578,-0.00445069,-0.004726799,0.01984095,0.0045255343,-0.005847579,-0.02606015,0.011515744,0.002265362,-0.022159323,0.01717837,-0.044551127,0.029452533,-0.006497393,-0.023854047,-0.05131344,-0.045966987,-0.055736076,-0.0014474381,-0.025015835,0.07076286,-0.03728993,0.038816765,0.05994495,-0.05802629,0.013934975,-0.024384227,0.020931674,-0.011537991,0.01534293,0.010324816,0.008599567,0.020400006,-0.013898819,-0.0023636336,0.00546297,-0.0034331877,-0.023794023,0.017741052,0.002995082,-0.022399845,0.02244931,-0.048432782,0.030007178,0.027582271,-0.03630813,-0.007734855,0.016832842,-0.013486857,-0.031616177,0.03696953,-0.009857931,0.02324236,0.05026383,0.016010555,-0.0018516623,0.015227154,-0.007226003,-0.015452213,-0.04090959,-0.0073361136,-0.03831342,-0.04839669,-0.0025614137,-0.050854605,0.015302