INSERT INTO document_chunks VALUES (7, 4, 'This chunk illustrates the Blending System example setup, including the system notation, operating assumptions, control objectives, and key terminology that will be used throughout the analysis. The blending system consists of a mixing vessel with two input streams and one output stream. The notation is defined as follows: $w_1, w_2,$ and $w$ represent the mass flow rates, while $x_1, x_2,$ and $x$ represent the mass fractions of component A for each respective stream entering and exiting the vessel. The system operates under three primary assumptions: the flow rate $w_1$ is constant, stream 2 is pure component A ($x_2 = 1$ and constant), and there is perfect mixing within the tank. The Control Objective is to maintain the output concentration $x$ at a desired set point $x_{sp}$ by adjusting the flow rate $w_2$, despite time-dependent variations in the inlet concentration $x_1(t)$. In this system, $x$ is the Controlled (output) variable, $w_2$ is the Manipulated (input) variable, and $x_1$ is the Disturbance (load) variable.', '[-0.025537785,-0.011181911,-0.058888193,0.027756602,-0.012781897,-0.04180492,0.0036004018,0.049413543,-0.009747144,0.045631286,0.001060743,-0.04035922,0.030459924,-0.005053529,0.013160894,-0.001996157,0.0026458793,0.0058926526,0.021162411,-0.009556711,-0.0102822995,0.013329041,0.012461639,-0.0034600452,0.023878023,0.038658734,-0.023298157,-0.02025336,0.022343343,0.05144516,-0.0028050756,-0.0089665,-0.0375407,0.00095721043,0.007857295,-0.026918087,0.01218114,-0.024365222,-0.040576678,0.07632347,-0.0056633935,0.0031468498,-0.03942221,-0.04063155,0.064262465,-0.020391827,-0.02522936,-0.055925827,-0.052546863,-0.003106463,-0.0456204,0.0065921033,0.035114914,-0.021571761,0.025094418,0.0076017375,-0.09617643,0.014711802,-0.049876258,0.00033493253,-0.028500792,0.056069758,-0.03740953,-0.0062156715,0.0044918526,0.0075847553,0.0025058684,0.03683996,-0.03185985,-0.051356383,0.021871,0.023946565,0.040523924,0.0