INSERT INTO document_chunks VALUES (11, 4, 'This chunk introduces two additional control strategies, including Combined Feedforward/Feedback and Design Changes. Method 3 involves a combined strategy where both $x_1$ (disturbance) and $x$ (output) are measured to adjust $w_2$, leveraging the advantages of both feedforward and feedback control. Method 4 suggests a Design Change" by using a larger tank. If a larger tank is used, fluctuations in $x_1$ will tend to be damped out due to the larger capacitance of the tank contents. However, this strategy involves higher capital costs compared to implementing active control logic.', '[-0.035875898,-0.021086527,-0.023651652,0.0022783256,-0.020994196,-0.033378303,0.0061673615,0.051024776,-0.010123782,0.048898257,-0.02115532,-0.020584138,-0.014347784,-0.009557402,-0.03758131,-0.024868274,-0.0194954,-0.0011316191,0.020510081,-0.051552188,0.010829386,-0.025996827,0.006778195,0.038393978,-0.010846682,0.025972268,0.0050792247,-0.031212153,0.036589995,0.082980506,0.029706977,-0.014776942,-0.029270396,-0.010340094,-0.0075185583,-0.021492884,-0.00018918315,-0.052995663,-0.043004345,-0.009511501,-0.023620494,-0.012827484,0.017791186,-0.031854965,0.036838945,-0.010167768,-0.015621556,-0.033475522,-0.016450461,-0.010542252,0.013932003,-0.020630173,0.038870707,-0.040881626,0.009611538,0.027650539,-0.046598423,-0.011595867,-0.013802731,0.041395318,-0.0509587,0.01629237,-0.014569063,-0.019587832,0.03521265,0.04188332,-0.0033002621,0.039805707,-0.016782798,-0.060699668,-0.0022112422,0.0063294773,-0.006199915,-0.01230909,-0.054175023,0.015235138,0.011741013,-0.040291153,0.07449507,0.030145127,-0.012018573,-0.023848651,0.013674507,-0.012543029,0.0062169647,0.028344616,-0.008658909,0.0069353036,0.018336346,0.0035785646,0.003880968,-0.030067412,0.030295901,-0.041357663,0.023564648,0.019285794,-0.04411248,0.0116792405,0.01851173,-0.005750115,-0.0015836491,0.058152314,-0.01640372,-0.051092662,0.046751086,-0.01752395,0.06789361,0.011708928,-0.0019