INSERT INTO document_chunks VALUES (12, 4, 'This chunk provides a summary table classifying all the four control strategies for the Blending System. The control strategies for the blending system are classified based on their measured and manipulated variables. Method 1, which is Feedback Control strategy, measures $x$ and manipulates $w_2$. Method 2, which is Feedforward Control strategy, measures $x_1$ and manipulates $w_2$. Method 3, which is Combined Feedforward/Feedback Control strategy, measures both $x_1$ and $x$ while manipulating $w_2$. Method 4, which is Design Change strategy, involves no measurement or manipulation of variables.', '[-0.028027024,0.009642538,-0.040143028,-0.007841324,0.0007899455,-0.023365794,-0.0002160339,0.04718907,-0.0071118283,0.051630367,-0.022246325,-0.0032521323,0.039064325,-0.0058918158,0.0013255241,0.019592293,-0.019060675,-0.015307774,0.018859679,-0.058496937,-0.019306926,0.025974955,0.003228893,0.014372269,0.019672854,0.015754212,-0.020104736,-0.017090332,-0.0020323684,0.06763252,0.01871128,-0.0250287,0.0017319836,-0.008366092,-0.036877938,-0.013096758,0.018295875,-0.06313172,-0.024185956,0.021789258,0.0014581351,0.0042925794,-0.0037595956,-0.046553057,0.037607312,0.00526556,-0.0013504484,-0.046624005,-0.044485662,-0.022379199,-0.0051315846,0.020711008,0.025459846,-0.042648725,-0.010221773,0.050294783,-0.05163778,0.004941889,-0.053238206,0.039487273,-0.024432823,0.012944221,-0.029971901,-0.022446161,0.03149519,0.017236173,-0.003840619,0.03684411,-0.02916545,-0.049721263,0.0063335383,0.052935284,0.02321174,0.009344459,-0.06833893,0.012585788,-0.02193116,-0.017306257,0.01963045,0.020299522,-0.022106428,-0.016394684,0.0006448873,0.023969613,-0.012725837,0.036425292,0.015871214,0.0032969425,-0.0057969885,0.0072282585,0.01446515,0.014585706,0.00877116,-0.044441987,-0.018452706,0.013851959,-0.0024318164,0.011284195,-0.015964203,0.00019937605,-0.028551143,0.026083928,-0.015473122,-0.022953933,0.004352626,-0.038691886,0.03471437,0.0292