INSERT INTO document_chunks VALUES (13, 5, 'This chunk analyzes feedback (FB) control strategy by explaining its distinguishing feature, its advantages and disadvantages. The distinguishing feature of feedback control strategy is that it measures the controlled variable, and that it exhibits negative feedback in engineering applications, which is desirable for stability, in contrast to positive feedback common in social sciences. The advantages of feedback control are that corrective action is taken regardless of the source of the disturbance, and that it reduces sensitivity of the controlled variable to disturbances and process changes. The primary disadvantage is that no corrective action occurs until after the disturbance has upset the process, that is, until after $x$ differs from its set point.', '[-0.024527503,-0.010718357,-0.026289238,-0.010527765,-0.014633672,-0.043716542,0.03230164,0.036156293,0.026232066,0.06866699,-0.025943166,-0.015992718,-0.0017530748,0.000112060115,-0.026981935,0.013082146,0.007339574,-0.019087795,-0.017279545,-0.027926007,0.017378574,0.016743584,-0.020952329,-0.007828567,0.0050980193,0.046453122,-0.0053603374,-0.008105214,-0.0070922105,0.087476775,0.0018906771,-0.018233068,0.0092541985,-0.0016960694,-0.036818378,-0.008354205,0.014434028,-0.05462808,-0.02367708,-0.019952638,-0.021513823,-0.007818342,0.033263694,-0.028413534,0.015269404,-0.02117243,0.015819052,-0.020838207,-0.019550325,-0.013788414,0.04573373,-0.031591635,0.0662145,-0.03579334,0.024352549,0.019946055,-0.0012103321,-0.006898278,0.014135057,0.011116709,-0.021501737,-0.019830298,-0.004894125,-0.022462763,0.026355913,0.03146832,-0.02951048,-0.0141902,-0.014787666,-0.065265395,0.037557308,0.018099789,-0.002162515,-0.013324462,-0.03562801,0.030378738,-0.01607292,-0.048853643,0.009019171,0.007072771,-0.041739326,0.0018686352,0.057159103,0.005783694,0.020462124,0.0037763,-0.011063257,0.034644034,-0.022769393,-0.0010277744,-0.008205441,-0.014087056,0.03606698,-0.008256074,-0.009