INSERT INTO document_chunks VALUES (14, 5, 'This chunk analyzes feedforward (FF) control strategy by explaining its distinguishing feature, its advantages and disadvantages. The distinguishing feature of feedforward control strategy is that it measures the disturbance variable. The key advantage is that it can correct for disturbances before they upset the process, providing proactive rather than reactive control. However, the disadvantages of feedforward control are: it must be able to measure the disturbance, secondly no corrective action is taken for unmeasured disturbances that may affect the process, and lastly, a process model is required to determine the appropriate control action based on the measured disturbance.', '[-0.016978685,-0.009892275,-0.0405867,-0.009147317,-0.0230137,-0.015809596,0.0068651135,0.07073754,0.0055641853,0.061625835,-0.044947796,-0.040203106,-0.012901134,-0.0030975938,-0.0068915095,0.002757934,0.022744812,-0.036801435,-0.00484271,-0.045850147,0.022400483,0.018203614,-0.016015025,0.0024368623,0.022033915,0.040874977,-0.00033965308,-0.024586305,0.019603452,0.066590555,0.0069828215,-0.015015947,-0.009355302,-0.0032284593,-0.023635447,-0.0029103532,0.010752483,-0.04171289,-0.021559518,-0.016071113,-0.028360082,-0.0045717843,0.009494753,-0.04469765,0.023228217,-0.02934442,0.0050593847,-0.02823088,-0.04320401,-0.011618539,0.013971568,-0.02875524,0.07061504,-0.025590966,0.05999085,0.020395642,0.000109090084,-0.015780646,0.021365702,0.011370269,-0.03154196,-0.01838589,-0.009264636,-0.024566097,0.024105333,0.017745258,-0.0123104835,-0.01901062,-0.008756496,-0.05673611,0.034437258,0.03551792,0.006949394,-0.019341959,-0.04158618,0.021832215,-0.028963175,-0.016413217,0.027363656,0.010225495,-0.026748212,0.0051834323,0.052502844,-0.02678511,0.033993717,0.016262854,-0.004161551,0.048484806,0.0060610324,0.007828022,0.0030912003,-0.038760774,0.033051275,-0.031181868,-0.011868506,0.0015611695,0.0023227774,0.023016864,0.022310765,-0.017924543,-0.0236465