INSERT INTO document_chunks VALUES (15, 6, 'This chunk describes the four control elements of the control system (process, measuring element, controller and final control element). Process is the first control element and can be represented by a process model that relates input variables with output variables, where input variables can be either manipulated or disturbance variables. Output variables are the controlled variables that we want to maintain at desired values called set points. The second control element is the measuring element (sensor) which measures the controlled variable using devices such as thermocouples for temperature or gas chromatographs. The third control element is the controller that converts the actual set point into an equivalent internal signal, calculates the error by subtracting the measured value from the set point (desired value of the controlled variable), and calculates the controller output p(t) from the proportional control law. Finally, the final control element, typically a control valve, acts on the controller output and drive the controlled variable toward the set point.', '[-0.0049505816,0.01105834,-0.061739963,0.015717363,-0.008045318,-0.03804328,-0.012285305,0.04025093,-0.012105297,0.029290667,-0.01868963,-0.012339988,0.041371137,-0.012426312,-0.0060372753,0.022542253,0.035239834,-0.006212877,0.041045457,-0.045316003,-0.0051610004,0.016407164,-0.028682522,0.005607582,0.035925202,-0.01915778,-0.008784515,-0.0056248866,0.0030088262,0.05672779,-0.0023168281,-0.027972959,-0.015555866,-0.005333435,-0.048221134,0.004547707,0.016133375,-0.058736548,-0.03668384,0.043518674,0.0051613366,-0.056084063,0.01751717,-0.05533599,0.008252366,-0.0388192,-0.0014797966,-0.045405976,-0.03427669,-0.022389464,-0.01511222,0.029817715,0.026380887,-0.08201321,0.010728683,0.0667409,-0.10363053,0.0002711194,-0.042477705,0.0432307,-0.03126349,0.0119367745,0.0074952035,-0.021505713,0.045660295,0.02787739,0.015077168,0.009793936,-0.010744308,-0.008928264