INSERT INTO document_chunks VALUES (16, 7, 'This chunk explains the purpose and structure of block diagrams as a tool for representing control systems and the difference between open loop and closed loop configurations. Block diagrams represents the physical connections between the components of the control system and illustrates the flow of information within the control system, including the input and output signals associated with each component. It enables visualization of overall process behavior by depicting one block for each element of the control loop, with each block/ component containing a corresponding mathematical model. Block diagrams are classified as either open loop, where there is no feedback from the output to the input, or closed loop, where the output is measured and fed back to compare with the set point.', '[-0.0069812806,-0.018513331,-0.0521909,0.005040004,-0.023502117,-0.034276895,0.016217511,0.010073026,0.018432347,0.031193735,-0.021919988,-0.008579049,0.013680947,0.015865643,-0.039955944,0.025593746,0.026077265,-0.0038329896,0.019637764,-0.013587603,0.00084623724,-0.02846351,-0.008450636,-0.0033223454,-0.00630745,0.035982672,-0.0019139939,0.022611901,-0.00528655,0.05426927,0.04320661,-0.011766417,-0.00708197,0.020485772,-0.010422234,-0.018856486,0.022792444,-0.021057915,-0.024972167,0.023201186,-0.0022815727,-0.004644601,0.014189045,-0.033936664,0.005976955,-0.0012013317,-0.018431569,-0.041295268,-0.030773597,-0.04390216,0.014333419,-0.014176868,0.029465016,-0.050628364,0.009311886,0.030685047,-0.062902585,-0.040418155,-0.06915331,0.0044887606,-0.016026467,0.007008112,0.03047887,-0.02423862,0.01585831,0.027034251,-0.0020832252,0.018968059,-0.023249963,-0.015052241,0.0034138123,-0.011083509,-0.018024143,-0.018800005,-0.0033779412,0.03930705,-0.0073493905,-0.042367477,-0.05447229,0.03137739,-0.02263298,-0.027756745,0.012023651,-0.021825757,-0.019750515,0.028843096,0.00842282,0.06650361,-0.022033526,0.011470941,-0.0022807233,-0.01824965,0.055