INSERT INTO document_chunks VALUES (20, 10, 'This chunk describes theoretical modeling as one of three key modeling approaches in Process Control. Theoretical models are developed using first-principles of chemistry, physics, or biology, including material and energy balances, heat, mass and momentum transfer, thermodynamics, chemical kinetics, and physical property relationships. These models provide physical insight into process behavior and are good for extrapolation and scale-up to different operating conditions. The advantages are that theoretical models do not require experimental data, though data is still required for validation and parameter fitting. However, theoretical models are expensive and time-consuming to develop, and model parameters are not always readily available.', '[-0.012224936,-0.005422652,-0.047172777,0.028354637,-0.01889434,-0.038405225,-0.01578705,0.047505815,-0.0025243543,0.019646503,-0.07272264,-0.03395294,0.003331364,-0.012339552,-0.007854381,0.041308276,-0.0037543855,0.010430544,0.017242255,-0.034650024,0.021712974,-0.014215201,0.037667762,-0.03365032,-0.007911654,-0.0084701935,0.0037719125,-0.019788483,-0.015539777,0.021522943,0.005728038,-0.025057413,-0.028490895,-0.0010952548,-0.03098002,0.008696688,0.018837603,-0.043128077,-0.017932782,0.027999073,0.01759235,-0.080354735,0.012990468,-0.013295299,0.005783047,-0.021349603,-0.042227827,-0.04913829,-0.048383296,-0.06817768,0.012393595,0.0017152326,-0.0077882144,-0.041751243,0.034505818,0.046480745,-0.07160674,0.0068320935,-0.08118269,0.017765392,-0.07988966,0.017613512,0.013798976,0.0092348205,0.021926621,0.0035288115,-0.026553461,-0.0029567129,-0.006341251,-0.06360399,0.016287973,-0.022750368,-0.008528691,-0.03146984,-0.031553704,0.020858146,-0.036394775,-0.041418336,-0.00013185156,0.054812115,-0.03163083,-0.014952493,0.036816206,-0.02563033,0.0649952,0.0036321564,0.016975142,0.0027014322,0.022400932,-0.020095615,-0.019454142,0.0039803274,0.007906103,-0.02792384,-0.01364262,-0.013084