INSERT INTO document_chunks VALUES (21, 10, 'This chunk describes the second key modeling approach, empirical modeling (black box approach), which is an alternative to theoretical modeling. Empirical models, also called black box models, are obtained by fitting experimental data. These models are easier to develop than theoretical models and typically use linear regression techniques. However, empirical models have a significant limitation in that they do not extrapolate well beyond the range of conditions covered by the experimental data used to fit them.', '[-0.06255481,-0.032049343,0.001832117,0.011128299,-0.012277053,-0.032556854,0.013794701,0.060805373,0.012333116,0.049416773,-0.0542169,-0.014691399,-0.016982459,0.034800306,0.016149705,0.03566899,0.002490323,0.01657025,-0.00594861,-0.017233,0.031206459,-0.004778774,0.019431645,-0.0036620537,-0.06914365,-0.006767321,0.005481044,-0.021025129,0.023034899,0.012859001,-0.009417225,0.0020855376,-0.041666757,-0.0007813959,-0.03596311,0.036417555,0.0026942545,0.0044257054,-0.022607306,0.015616338,-0.018386476,0.002914868,0.028928995,-0.070072114,0.039715998,-0.027975027,-0.005557603,-0.016386649,-0.0483037,-0.053152177,0.025723422,0.011935263,-0.006143159,-0.05437327,0.009649902,0.042483836,-0.0035088775,-0.006859355,-0.057989035,-0.0039638644,-0.060590636,0.024551596,-0.0036836453,-0.0021171805,0.013986399,-0.013168427,-0.0074315467,0.053529363,-0.015930483,-0.09343778,-0.025312576,-0.027343865,-0.022803446,-0.010280209,-0.008532851,0.013462865,-0.0002035772,0.010760736,-0.038284265,0.045801036,-0.016145026,-0.011285802,0.022785297,0.0019390668,0.033219274,-0.023346866,0.017279876,0.030666366,0.017059976,0.034871567,-0.008647206,-0.017075725,-0.021772288,-0.06679806,-0.019242764,-0.01966207,0.021882473,-0.01981707,0.0429221,0.026104273,0.001276997,-0.026432885,0.030110905,-0.050070304,0.022974279,-0.01819738,-0.025842445,0.047502626,0.01374857,-0.013214402,0.040756572,0.0274265,0.01664795,0.032100204,-0.014846506,-0.0