INSERT INTO document_chunks VALUES (22, 10, 'This chunk describes the third key modeling approach, semi-empirical modeling, as a hybrid approach that combines the strengths of theoretical and empirical methods. Semi-empirical models represent a combination of theoretical and empirical approaches whereby theoretical knowledge is incorporated and experimental data can be used to calculate numerical values of one or many parameters in the theoretical model. The advantages of semi-empirical models are that they can be extrapolated over a wider range of conditions compared to empirical models. At the same time, they require less development effort than theoretical models because not all parameters need to be determined from fundamental principles or extensive literature review. This makes semi-empirical modeling a practical compromise for many industrial applications.', '[-0.04524492,-0.012060356,-0.0042363326,0.011915504,-0.007167391,-0.037780017,0.014653009,0.053801835,0.020424703,0.02579241,-0.04805032,0.02151517,0.002132437,-0.012522815,0.008049057,0.018996952,0.02403868,-0.031257812,0.0012477583,0.008278899,0.0029085535,0.015180636,0.013355697,0.007514949,-0.024591494,0.004819882,-0.028747773,0.0044315956,0.005299722,0.029630866,-0.016148867,-0.018326217,-0.008580019,0.009484502,-0.041319575,-0.00198527,0.0031891689,-0.013039223,-0.023261124,0.0147559075,-0.009718437,-0.03571911,0.026127465,-0.06279974,0.021995809,-0.031117013,-0.038450275,-0.041015092,0.0015673406,-0.03953568,0.0063821296,-0.012283308,0.003772487,-0.06586249,0.023040103,0.049303412,-0.06540886,0.039369375,-0.08771113,-0.006059985,-0.064468846,0.029963873,0.013527965,0.007538723,0.0031169932,0.0004526493,-0.026044114,0.05035626,-0.014743311,-0.076109156,0.010152077,-0.016691433,-0.035706848,-0.01325561,-0.036033235,0.027323378,-0.03241999,-0.0046469625,-0.052678745,0.051656894,-0.03127208,-0.034886338,0.015141437,-0.018331338,0.01807877,-0.016268682,0.038581166,-0.008312684,0.027102187,0.002455532,-