INSERT INTO document_chunks VALUES (26, 12, 'This chunk introduces stirred-tank heating process as the second example, establishing the system configuration and the key assumptions. For a stirred-tank heating process with constant holdup V, the assumptions are perfect mixing, constant density and heat capacity of liquid, and negligible heat losses. The stirred-tank heating process involves an input stream at temperature $T_i$ and mass flow rate $w_i$, an output stream at temperature $T$ and mass flow rate $w$, and a heater that supplies heat $Q$.  Schematic of a stirred tank heater, with inlet stream characterized by temperature $T_i$ and flow rate $w_i$ and outlet stream characterized by temperature $T$ and flow rate $w$. The tank has a mixer with volume $V$ and a heater that provides heat $Q$.', '[0.010994623,-0.024895592,-0.053748403,0.05266521,0.02296803,-0.051970296,0.0038576408,0.025530504,-0.015015018,0.005228478,0.024752248,-0.03713459,-0.041597687,0.021368697,-0.010160562,-0.016263945,0.00043624899,0.05555097,0.04088168,-0.00841892,-0.010879564,0.028829148,0.009235763,-0.05481529,0.02736844,0.009216075,-0.009202093,-0.029058894,-0.00022746647,-0.0058540166,0.035042673,0.027190194,-0.07083783,-0.007908845,-0.0145774465,-0.027979355,-0.03446364,-0.01027972,-0.035272315,0.050836697,0.023327647,-0.04562952,0.025650525,-0.007232578,0.0524625,-0.021146018,-0.025947275,-0.034948554,-0.039531477,-0.02518071,-0.008381703,-0.007962353,0.025587182,-0.011831205,0.00934466,0.03272901,-0.062458728,0.0009792785,-0.06387974,0.04499813,-0.037149012,0.06309861,-0.022080472,-0.02375554,0.0012579298,0.013704099,0.04512426,0.029883085,-0.023019372,-0.058913276,0.019685438,0.0022184106,-0.0044423607,-0.0058733774,-0.036943994,0.055297405,0.05590492,0.005584115,0.015738372,-0.010345102,-0.020307466,-0.052824233,0.030251494,-0.014730215,-0.0021367783,-0.00782128,0.023076143,0.029067636,0.052233472,-0.03418488,-0.017128557,-0.024034565,-0.0030587981,-0.019574888,-0.0038458386,-0.01