INSERT INTO document_chunks VALUES (28, 12, 'This chunk introduces liquid storage systems as the third example, presenting the general mass balance for a cylindrical tank and explaining the key assumptions. For liquid storage systems receiving an inlet volumetric flow rate $q_i$ and discharging an outlet volumetric flow rate $q$ at liquid level $h$, the mass balance equation is $\frac{d(\rho V)}{dt} = \rho q_i - \rho q$ (Equation 2-53). Under the assumptions of constant density and that the tank is cylindrical with cross-sectional area $A$ and $V = AH$, this simplifies to the equation: $$A \frac{dh}{dt} = q_i - q$$ (Equation 2-54). An important note is that volume is not conserved for fluids due to constant density assumption. This equation forms the basis for analyzing three important variations of liquid storage systems.', '[0.01008955,0.008571548,-0.028244006,0.006300136,-0.010165242,-0.044048697,0.015938118,0.013213162,-0.015350378,-0.0052295336,0.018380366,0.0039576306,-0.03914175,0.030910436,0.011665042,-0.021992918,-0.006344094,0.011540479,-0.033363126,-0.0046080067,-0.014445646,-0.01579168,0.010343983,-0.00041254528,0.0016025645,0.041503213,-0.007201858,-0.015834088,0.015252202,0.025873927,0.027813682,0.0409233,-0.043448396,-0.02211367,-0.021923184,-0.012026363,-0.03339626,-0.020484917,-0.052249786,0.07279265,0.007820057,-0.035229426,0.02169569,-0.036599685,0.03714931,-0.04244293,-0.042639624,-0.059647713,-0.028813856,0.0075682253,-0.024377901,-0.015459402,0.053175658,-0.004147722,0.017954312,0.019653965,-0.047762707,-0.032096397,-0.033442754,-0.0023497783,-0.03383377,0.047918823,-0.039223466,0.0039145467,0.023094583,0.02091137,0.0020024215,0.0009695503,-0.02912722,-0.021710046,-0.013873886,0.013282746,-0.024208518,-0.0032358656,-0.055951916,0.014578215,0.03347558,0.004236502,0.025201064,-0.0017031764,-0.0029820804,-0.032175537,0.039060175,-0.042102937,-0.047550794,0.020993758,0.027212635,-0.013402465,0.042252727,-0.06183314,-0.052310586,-0.00085509225,0.011