INSERT INTO document_chunks VALUES (30, 13, 'This chunk motivates the need for Laplace transforms by comparing the difficulty of solving differential equations directly versus solving equivalent algebraic equations, introducing the concept of forward and inverse transformation mappings. When solving a first order chemical reaction described by the differential equation $\frac{dc}{dt} = -kc$ with the initial condition $c(t=0) = c_0$, whose solution in the time domain is $c(t) = c_0 e^{-kt}$, we face a choice between solving the differential equation directly or transforming it to an algebraic equation. The algebraic equation $sc - c_0 + kc = 0$ is much easier to solve for c, yielding $c = \frac{c_0}{s + k}$, which can then be inverse transformed to get the time domain solution $c(t) = c_0 e^{-kt}$. If there exists a mapping that transforms differential equations to algebraic equations and an inverse mapping that transforms the algebraic solution back to the time domain solution, this would provide a powerful tool for solving differential equations. This is what Laplace transforms accomplish.', '[-0.014329846,0.04723178,-0.03474441,0.018778246,0.0029732177,0.010067813,0.055575073,0.010530538,0.028684191,0.019808926,0.0009529218,-0.028787998,-0.020122241,0.022262752,0.007313887,0.01069181,0.025891585,0.009566657,0.02718907,-0.00456945,-0.02214742,-0.006246072,-0.008256557,0.007862042,-0.01035651,0.007894485,-0.019302886,-0.021825947,0.006943589,0.00090240844,-0.006147823,-0.0176632,-0.0014623525,-0.031233095,-0.0378491,-0.0004582379,0.005057515,-0.009567657,-0.030578865,-0.0025542176,-0.010154176,-0.010410047,0.05934708,0.009768381,-0.00023626571,-0.02176949,-0.03924038,-0.023823932,-0.00086562824,-0.042782586,0.010876174,-0.03344986,0.06221482,-0.047353376,-0.028873468,0.0083436705,-0.031338252,-0.05033878,-0.0590677,-0.033919588,-0.016936552,0.0035970835,-0.031476054,0.035662647,0.0040257676,0.0042019547,-0.029543813,0.024451923,-0.018241765,-0.046077702,-0.031646565