INSERT INTO document_chunks VALUES (33, 14, 'This chunk introduces the Laplace transform for basic time-domain inputs, specifically constant functions and step functions (Heaviside function), which are fundamental for analyzing sudden changes in dynamic systems in Process Control. The Laplace transform converts simple time-domain inputs into algebraic expressions in the $s$-domain. For a constant function ($a$), the Laplace transform is derived as $\mathcal{L}[a] = \int_{0}^{\infty} a e^{-st} dt = \frac{a}{s}$. The Step Function is defined as $f(t) = 0$ for $t < 0$ and $f(t) = A$ for $t > 0$, representing a sudden input change. The Laplace transform of the step function is $\mathcal{L}[f(t)] = \frac{A}{s}$. The Unit Step (Heaviside) Function is denoted as $u(t-c)$, it is $0$ for $t < c$ and $1$ for $t \ge c$.', '[-0.033987164,0.025989082,-0.04538733,0.024805566,0.020685392,-0.0062550674,0.039207216,0.029223833,0.02452262,0.024203626,-0.016327366,0.010545089,0.022526152,0.0055645686,0.023126602,-0.012447443,0.039399434,0.046902187,0.06817548,-0.0065214247,-0.025456708,0.02574147,-0.0029884195,0.0045414143,-0.04246138,0.030822027,-0.00882367,-0.024182059,0.007640988,-0.00834398,0.021083822,-0.0050314157,-0.057594575,-0.055573445,-0.04324307,0.05392046,0.0087713245,-0.022172078,-0.06081153,-0.013254582,-0.03162947,-0.041749652,0.051800594,0.0059349244,0.02636021,0.0095595,-0.00581328,-0.054591436,-0.02272092,-0.019074373,0.037776235,-0.029042548,0.059352588,-0.040190384,0.028870149,-0.02485475,-0.047706533,-0.026392322,-0.08797204,0.01571107,-0.045369856,0.038796082,-0.01570228,0.032004893,0.027983153,-0.00088286656,0.025519682,0.021579908,0.00620697,-0.010949249,-0.0108321,0.03199151,-0.058946613,0.014373037,-0.026816104,0.10600884,-0.007867067,-0.0062913024,-0.00030662614,0.049429353,-0.0050496473,-0.015699942,-0.024352457,-0.012657583,-0.0322204,-0.013146066,0.022984548,-0.01308789,0.0029628805,-0.0019055969,0.019772284,-0.0007272241,0.004753522,0.008254991,-0.01973