INSERT INTO document_chunks VALUES (35, 14, 'This chunk provides the derived Laplace transforms for common exponential and trigonometric functions used to model system responses in Process Control. These key transforms are essential for converting differential equations into algebraic ones. For exponential functions, if $f(t) = e^{-at}$, the transform is $\mathcal{L}[e^{-at}] = \frac{1}{s+a}$. Similarly, for $f(t) = e^{at}$, the transform is $\mathcal{L}[e^{at}] = \frac{1}{s-a}$ where $a \in \mathbb{R}$. For trigonometric functions, the sine transform is $\mathcal{L}\{\sin(\omega t)\} = \frac{\omega}{s^2 + \omega^2}$ and the cosine transform is $\mathcal{L}\{\cos(\omega t)\} = \frac{s}{s^2 + \omega^2}$ for $\omega \in \mathbb{R}$.', '[-0.011503564,0.0473205,-0.030470056,0.0006895736,0.008355692,-0.03362713,0.013656267,0.023398522,-0.007757856,0.031661976,-0.028358575,0.028815277,-0.03075976,0.031135488,0.009225658,0.0037015416,0.056911875,0.020061916,0.04121431,-0.008838227,-0.015209025,0.018327324,-0.014869868,0.010463984,-0.053080436,0.018871533,0.03235433,-0.035501268,0.023002064,0.010426962,-0.012323779,-0.013689801,-0.05346037,-0.027481042,-0.0454745,0.024245247,0.011331854,-0.028768003,-0.052904025,-0.022894049,-0.01792578,-0.035043858,0.054676954,-0.00787384,0.019188385,0.0073180147,-0.010750034,-0.055327896,-0.034032173,-0.022445474,0.03206375,-0.03529949,0.04516411,-0.025014106,-0.0023454672,0.012908457,-0.03918595,-0.009834848,-0.074591905,-0.01375283,-0.055826485,0.02887907,-0.035586964,-0.002300425,0.00961074,-0.008012149,0.030761965,0.02619525,0.013909289,-0.0127765685,-0.027707424,0.037803482,-0.048938397,-0.013638931,-0.064761154,0.059821993,-0.015951537,0.0047821924,0.013524925,0.063504614,-0.00083013956,0.013445335,-0.026794955,-0.007087936,-0.024010185,-0.018621843,0.026098592,0.0088164415,-0.021763824,0.0041788225,-0.034373097,-0.015941659,-0.016762083,-0.0027093727,-0.039942086,-0.044695776,-0.042728484,0.022954866,0.025463158,0.03638355,0.046061