INSERT INTO document_chunks VALUES (37, 14, 'This chunk explains the Time Delay property of Laplace transforms, used for systems with transportation lags or delayed responses in process engineering. For a function $f(t-t_0)$ shifted right by $t_0$, the Laplace transform is:$$\mathcal{L}[f(t-t_0)] = e^{-st_0} F(s)$$To invert a function containing $e^{-st}$, first invert $F(s)$ to the time domain, then replace $t$ with $(t-t_0)$, and finally multiply the entire function by the unit step function $u(t-t_0)$.', '[-0.016290188,0.019032251,-0.016716598,0.040088512,0.0052728453,0.013560987,0.0025994184,0.038418114,-0.012388411,0.023553858,-0.019409766,0.024464615,-0.017338842,0.014803316,0.038110506,0.0033691628,0.028247593,0.032381263,0.008779213,-0.03131726,0.020356547,-0.019136874,-0.033406936,-0.024195382,0.0068641407,0.01110335,-0.0019024021,0.004494267,0.036585394,0.017538223,0.013588659,-0.0038158009,-0.018911581,-0.02030503,-0.06741945,-0.009141963,0.025906969,-0.014684177,-0.046282195,0.012752678,-0.012230948,-0.017456273,0.046107177,-0.008445869,0.015178228,0.011903379,-0.0075735524,-0.02634175,0.0012193776,-0.034944776,0.009429669,-0.03858715,0.06929127,-0.040556226,-0.0018602589,0.0045985403,-0.0546184,-0.0488742,-0.07417427,0.013999866,-0.030592466,0.046468575,0.01696753,-0.02916146,0.030649845,0.022951193,-0.010112217,0.027336303,0.0024190038,-0.03757443,0.015091319,0.043177035,-0.06071715,-0.009865232,-0.040166408,0.07714775,-0.017595826,0.023444245,0.005923937,0.057981748,0.004345889,-0.0209942,0.026636306,-0.0168122,0.024322813,-0.033890504,0.0059340117,0.002611812,-0.031418983,-0.016652191,0.0038646127,-0.018360153,-0.027193604,-0.0066058687,-0.02457736,-0.054679576,-0.033166036,0.053477593,0.019499386,0.007132024,0.047449343,-0.012334109,0.0017928128,-0.027819106,0.01957813,-0.049000364,-0.02809041,0.027932726,0.0761231,-0.016156573,0.035670884,0.024125896,-0.002498173,0.03478728,-0.013573078,-0.015063984,0.020941729,-0.05199998,0.00461699,-0.039511018,-