INSERT INTO document_chunks VALUES (41, 15, 'This chunk covers other Laplace properties, such as Initial and Final Value Theorems as well as the Laplace of an Integral. The Initial and Final Value Theorems are useful for evaluating the initial and final values of a function. The Initial Value Theorem states $\lim_{t\rightarrow0}f(t)=\lim_{s\rightarrow\infty}s F(s)$. The Final Value Theorem states $\lim_{t\rightarrow\infty}f(t)=\lim_{s\rightarrow0}s F(s)$. Laplace of an Integral is also another Laplace property.', '[-0.009096767,0.045984272,-0.009218498,0.0030500796,-0.0058111716,-0.006707623,0.027075985,0.035690732,0.0057295817,-0.0054342644,-0.04457472,-0.017069004,-0.013315027,0.008569842,0.030401215,0.040964678,0.036600284,0.00037962827,-0.036443397,-0.021564482,-0.005199825,0.01801992,-0.014071663,0.011509721,-0.02760832,-0.003503509,0.036215745,-0.019993396,-0.013517195,0.04074667,0.011269944,0.00378931,-0.012420358,-0.023709789,-0.017002974,-0.025023531,0.044014975,-0.017669944,-0.03381244,0.019366018,-0.035788342,-0.02298507,0.040378515,0.020424195,-0.0083103655,-0.011159794,-0.015438067,-0.04526605,-0.015584994,-0.046815205,0.011137197,0.0015414276,0.027781116,-0.03529891,-0.011649401,0.047272034,-0.06488106,-0.04125435,-0.073691614,-0.009803665,-0.020519225,0.025952017,-0.018086959,-0.0043383585,0.038945135,0.0055297324,-0.017206915,-0.0010654221,-0.011846449,-0.012647566,0.039368242,0.03583775,-0.044072792,-0.024345636,-0.016740428,0.07050362,-0.0073117022,0.023168553,-0.0047455328,0.01782526,-0.01621487,-0.005288426,0.02067285,-0.004821515,0.02520831,0.010511812,0.030979846,0.039403185,0.010682248,-0.026117243,-0.020618953,-0.016274745,0.04205206,-0.007245821,-0.0023327956,-0.004252008,-0.058909815,0.046086263,0.022220703,-0.0135454815,0.03246332,0.013136998,0.011692039,-0.0047946596,0.045389473,-0.04122392,-0.040453862,0.007183894,0.03817073,-0.011704467,0.036095567,0.026638616,0.02724735,-0.017475367,-0.019147158,0.02945878,0.030957669,-0.022202723,0.01