INSERT INTO document_chunks VALUES (45, 16, 'This chunk details the Partial Fraction Expansion method for the first case where the denominator polynomial has all real and distinct roots. When the denominator polynomial $q(s)$ has $n$ distinct real roots, $F(s)$ can be expanded into the form:$$F(s)=\frac{p(s)}{q(s)}=\frac{\alpha_{1}}{(s-\beta_{1})}+\frac{\alpha_{2}}{(s-\beta_{2})}+\dots+\frac{\alpha_{n}}{(s-\beta_{n})}$$Here, $\alpha_i$ and $\beta_i$ are real numbers. To find a specific coefficient $\alpha_{i}$, one multiplies the entire expression by the corresponding factor $(s-\beta_{i})$ and evaluates the result at the root $s=\beta_{i}$. This isolates the coefficient for that specific term.', '[-0.016956603,0.005431831,-0.01861798,0.028466739,-0.028273594,-0.0664008,0.05086772,0.0049655223,0.020120041,0.03342296,-0.035440825,0.04343806,-0.068758994,0.001954759,0.057629,0.009349294,0.0029336624,-0.02381277,0.018131586,-0.026082996,-0.031879254,0.0018550878,-0.030969245,0.032560993,-0.020909768,0.024619764,0.019577205,-0.0014979712,0.06796795,0.013349224,0.023734117,0.020056432,0.04664237,-0.009113515,-0.04191662,0.0038926064,-0.032511815,-0.04267488,-0.018063372,0.010577167,-0.0014255402,0.015881846,0.0368147,-0.040438823,0.020716785,-0.01416038,-0.023150584,-0.057308085,0.013310175,-0.01775982,-0.012462483,0.0039231745,0.039749455,-0.03404808,-0.0031916283,0.03200145,-0.06419433,-0.027336989,-0.05584267,0.01571385,0.010619408,0.050446145,-0.073998116,-0.02886583,0.028421683,-0.030237513,0.0102774,0.039341647,0.009621292,-0.03287829,0.0023387144,0.037914615,-0.016220897,-0.034581248,-0.048356127,-0.014533398,0.015900409,0.028056046,-0.0019062157,0.008589777,-0.009646239,-0.022495242,-0.021308003,-0.021652406,0.0018320521,-0.01747524,0.028625138,0.031502243,-0.015185108,0.009835348,-0.028350836,0.011578951,-0.0038534019,-0.0435802,0.0074119368,0.016291915,-0.05977792,0.049130965,0.024406314,0.017479014,0.010575903,0.031463657,0.005406517,-0.023905922,0.0061714784,