INSERT INTO document_chunks VALUES (47, 16, 'This chunk details the Partial Fraction Expansion method for the case where the denominator polynomial has repeated roots. If the denominator $q(s)$ has a root repeated $r$ times, the Partial Fraction Expansion must include a term for each power of the factor up to $r$. The expansion takes the form: $$Y(s)=\frac{p(s)}{q(s)}=\frac{\alpha_{1}}{(s+b)}+\frac{\alpha_{2}}{(s+b)^{2}}+\dots+\frac{\alpha_{r}}{(s+b)^{r}}+\dots$$. Coefficients for these terms are found through differentiation or algebraic manipulation to isolate the specific constants associated with each power of the repeated root.', '[-0.024473181,0.0057648513,-0.02093095,0.045375597,-0.011414003,-0.053597227,0.09112261,0.008896571,-0.018060487,0.022601768,-0.010278071,0.03599559,-0.064236715,0.021779459,0.034113284,-0.015180086,0.009497438,0.014073443,0.03135505,-0.018456629,-0.016022524,0.010326516,-0.023236465,0.030184435,-0.03178899,0.03069703,-0.0084264595,-0.008505816,0.06351628,0.013915923,0.030783277,-0.0124653615,0.050689287,-0.022478629,-0.034835033,0.0034473236,-0.012046347,-0.042890847,-0.021640599,0.022566998,-0.016589098,0.008621128,0.016647035,-0.055211335,0.044858675,-0.009070289,-0.004764092,-0.045720965,0.036924295,-0.023950102,-0.011700044,-0.03424649,0.08579213,-0.027770791,-0.010017819,0.02348165,-0.04559262,-0.01022518,-0.054538835,0.031324536,-0.026303949,0.0326063,-0.07854532,0.010387244,-0.013018492,-0.0114013655,0.014695715,0.04184323,0.0069517023,-0.0018134372,-0.004880849,0.040444255,-0.036119998,-0.012261217,-0.069819026,0.011559455,0.020871792,0.01617741,-0.01951667,0.016484445,-0.018303737,-0.025554538,-0.020344129,-0.007932027,-0.012762864,-0.007321023,0.012990746,0.02158327,-0.017627979,0.012095475,-0.020620098,0.002297063,-0.017992098,-0.02489787,0.011276071,-0.006107822,-0.070418,0.024086978,0.02322579,0.03525885,-0.0068625174,0.016486157,0.0063418294,-0.018296756,0.0008287817,0.011827506,-0.06546461,0.019445306,0.029875368,-0.03