INSERT INTO document_chunks VALUES (86, 25, 'This chunk discusses the special case of a system having a pole at zero, leading to marginal or critical stability. When a system has a pole at zero ($\alpha = 0$), the partial fraction expansion of the impulse response $Y(s)$ includes a term of the form $\frac{a}{s}$. The inverse Laplace transform of this term is a constant value $a$. In this case, the response $y(t)$ is bounded but does not asymptotically return to zero as time increases. Systems with a pole at zero lie on the boundary of stability and are called marginally or critically stable systems.', '[-0.04080197,0.03170818,-0.028448762,0.019876193,-0.0060345163,-0.04134798,0.02077639,0.064616136,0.023068251,0.016457452,-0.03224327,0.015088638,-0.021296658,0.013013663,0.01808524,0.016501883,0.04069582,0.019755378,0.016968807,0.004944605,-0.025402812,0.012573601,-0.028544724,-0.013908481,-0.0010722931,0.03566763,-0.019311089,0.022929199,0.026776671,0.077075504,-0.009581243,0.00714456,-0.005965157,-0.030934358,0.016476862,0.00942486,0.00049527246,-0.0496981,-0.038459133,-0.00074040884,-0.036530137,-0.011582134,0.028274601,0.008303182,-0.009984329,-0.007996823,-0.023144206,-0.04630296,-0.022641776,-0.043822065,0.00016492918,-0.016674677,0.041314438,0.010201483,-0.026280532,0.02604322,-0.010622353,-0.024081623,-0.082354985,-0.0028343343,-0.02976843,0.026935652,-0.028391069,0.007859115,0.019421654,0.012370298,0.007486261,0.045130078,-0.0010481883,-0.05640635,0.03602646,0.017445488,-6.83423e-05,-0.018807376,-0.02877509,0.045651574,0.05454542,-0.008164104,1.7671595e-05,0.0093380045,0.008376441,0.0066010403,-0.046430677,0.016489796,0.0072741127,0.00909401,0.009931983,0.005139935,-0.03425531,-0.013922852,0.002796685,-0.0008843281,0.0075016124,-0.021958847,-0.024573093,-0.0023983468,-0.02094205,-0.0064260284,0.041139413,0.010666292,0.021327453,-0.02834666,-0.033973157,-0.029678784,0.012138464,0.018016262,-0.037330348,0.026046365,0.024692172,-0.026818193,0.017657112,0.042116