INSERT INTO document_chunks VALUES (55, 17, 'This chunk explains the Pure Integrator process using an example of a liquid level system with a constant exit flow rate. A liquid storage system where the exit flow rate $q_0$ is constant (e.g., pumped out at a fixed rate independent of liquid level) behaves as a pure integrator. The dynamic mass balance is $A\frac{dh}{dt}=q_{i}-q_{0}$. Subtracting the steady-state condition ($\overline{q}_i = \overline{q}_0$) yields the deviation equation $A\frac{dh^{\prime}}{dt}=q_{i}^{\prime}-q_{0}^{\prime}$. Taking the Laplace transform gives $AsH^{\prime}(s)=Q_{i}^{\prime}(s)-Q_{0}^{\prime}(s)$. If the exit flow $q_0$ is constant ($q_0''=0$), rearranging for the transfer function $\frac{H^{\prime}(s)}{Q_{i}^{\prime}(s)}$ results in $\frac{1}{As}$. This represents a pure integrator (ramp) for step change in inlet flow $q_i$.', '[-0.00452507,0.005916124,-0.02827948,0.022534326,0.0058447327,-0.03403631,-0.022500224,0.040062632,-0.0038246915,0.0560686,-0.0009271254,0.0009431167,-0.021823717,0.044699147,0.037684105,-0.011856716,-0.0076820957,0.020854268,0.018693725,-0.019139528,-0.005574751,0.005741913,0.027713696,-0.04667615,-0.017511833,0.0324095,-0.0068184105,0.025390448,0.015510991,0.039167155,0.0051054806,0.025787491,-0.074253805,-0.019061213,-0.013343854,0.00019916934,-0.021697694,-0.040692903,-0.039324235,0.07757914,0.0056828167,-0.025759049,0.00011983696,-0.03143951,0.051315766,-0.031978652,-0.033292618,-0.05387506,-0.026386196,0.0003412515,-0.017891807,-0.031492494,0.057196457,-0.03923334,0.011683488,0.02620111,-0.033569403,-0.026170503,-0.0356675,0.017130936,-0.020297073,0.07100274,-0.024551392,-0.020099219,0.022394963,0.028086878,0.015552164,0.005279792,-0.013899564,-0.020069908,-0.010270125,0.041401695,0.015104027,0.005815039,-0.049776934,0.03453457,0.045868937,-0.014549968,-0.0034199744,0.0048999833,0.013765938,-0.044549957,-0.004194118,0.03426252,-0.046856176,0.012630153,0.0017505711,0.009317644,0.026274774,-0.01596816,-0.0