INSERT INTO document_chunks VALUES (58, 18, 'This chunk discusses the fourth property of transfer function models, Physical Realizability, and the rules for combining transfer functions in series and parallel. For any physical system to be realizable, the order of the denominator must be greater than or equal to the order of the numerator ($n \ge m$). If $n < m$, the system response to a step input would be an impulse, which is physically impossible. When combining systems: For Transfer Functions in Parallel (Additive Rule), the outputs sum together: $Y=G_{1}U_{1}+G_{2}U_{2}$. For Transfer Functions in Series (Multiplicative Rule), the output of one becomes the input of the next: $Y=G_{1} \cdot G_{2}U$.', '[-0.04169822,0.008277851,-0.0071653207,0.019500881,0.0060492284,0.029120494,-0.024293048,0.023492504,0.011684473,0.03961049,-0.04297719,0.0053138025,0.022522874,0.0020092723,-0.003804128,0.0044650817,0.020939274,-0.007900233,0.018411225,0.017837798,0.028460115,0.011586258,-0.021662224,0.032297757,-0.028026514,0.013946397,-0.020630548,-0.0072289356,-0.015614179,0.090581864,0.01664031,-0.037465595,-0.012548168,-0.044468448,-0.034858257,-0.008483215,-0.025007876,-0.009062131,-0.029833611,0.02980119,-0.043897763,-0.0087056095,-0.0008838989,-0.0498745,-0.008703222,-0.042683206,0.019417323,-0.028686108,-0.050744124,-0.050094783,-0.033566665,-0.013173665,0.036456894,-0.038656298,-0.013928852,0.02603717,-0.035786904,0.016361168,-0.039610565,0.005156278,-0.02172383,0.03820019,-0.028058454,-0.018848013,0.05177599,-0.002410847,0.023355095,-0.022653375,0.0043051923,-0.041771445,0.020795267,0.03366137,-0.035061054,0.0038605032,-0.07201227,-0.0028055047,-0.021149278,-0.0318719,-0.011438742,0.04670389,-0.024895238,-0.025621792,0.03577883,-0.016860256,-0.009038292,0.025183164,0.011413275,0.022877535,0.013327464,0.007566057,0.00073041994,0.007766745,-0.0141075635,-0.04208728,4.0182065e-05,-0.013571257,0.00889551,0.010614803,0.03638686,0.015904177,-0.02807556,-0.004301574,-0.030301