INSERT INTO document_chunks VALUES (60, 19, 'This chunk demonstrates how to linearize a general nonlinear ordinary differential equation with two variables using partial derivatives. For a nonlinear dynamic model where $y$ is output and $u$ is input, given by $\frac{dy}{dt}=f(y,u)$, the function is approximated around the steady state $(\overline{y}, \overline{u})$. The linearized expansion is: $$f(y,u)\cong f(\overline{y},\overline{u})+\frac{\partial f}{\partial y}|_{\overline{y},\overline{u}}(y-\overline{y})+\frac{\partial f}{\partial u}|_{\overline{y},\overline{u}}(u-\overline{u})$$. Since at steady state $f(\overline{y},\overline{u})=0$, the linearized deviation model becomes: $$\frac{dy^{\prime}}{dt}=\frac{\partial f}{\partial y}|_{s}y^{\prime}+\frac{\partial f}{\partial u}|_{s}u^{\prime}$$. This derivation naturally introduces deviation variables into the equation.', '[-0.045918602,-0.012308477,-0.019887818,-0.027873307,0.025267625,0.028625531,0.0039844867,0.025012152,0.039895285,0.02617175,-0.0070929583,0.01811095,-0.015532705,-0.0015782296,-0.012066786,-0.035803024,0.016632544,0.06172168,-0.00011515399,-0.028934214,-0.03835582,-0.014059225,-0.021517428,0.0133814765,-0.03583381,0.019164508,0.016929014,-0.0017867849,0.028336622,0.051107127,0.03108092,0.01536079,-0.029229455,-0.05518133,-0.010464426,0.07381434,-0.021062108,-0.0039390367,-0.04313251,0.01269465,0.019061161,0.013786457,0.049011096,-0.022525815,0.040756315,-0.017416293,-0.0016997962,-0.042500384,-0.016204385,-0.03357558,-0.020765543,-0.034579843,0.068099186,-0.031619173,0.025397673,-0.009701472,-0.020603897,-0.026509082,-0.08957438,-0.0011136446,-0.055419583,0.013449379,-0.01537681,0.0114812255,0.017191509,0.017372498,0.022966009,0.063362926,-0.0015926777,-0.021698758,-0.0015613246,-0.01665269,-0.013798825,0.004116362,-0.07284857,0.015169274,0.026631344,-0.026728978,0.016289655,0.0008605782,0.016808996,0.02152264,0.0029838185,-0.0059139132,-0.022139147,-0.005155359,0.048442982,0.050556798,0.0372665