INSERT INTO document_chunks VALUES (61, 19, 'This chunk provides a specific example of linearizing a process with a nonlinear flow control valve. Consider a tank where the outflow $q$ is controlled by a valve with nonlinear characteristics given by $q=C_{v}\sqrt{h}$. The dynamic model is $A\frac{dh}{dt}=q_{i}-C_{v}\sqrt{h}$. To linearize this around the steady state, we evaluate the partial derivatives. The linearized equation becomes: $$A\frac{dh^{\prime}}{dt}=q_{i}^{\prime}-\frac{1}{2}C_{v}\overline{h}^{-0.5}h^{\prime}$$. Rearranging this into standard form yields: $$A\frac{dh^{\prime}}{dt}=q_{i}^{\prime}-\frac{1}{R}h^{\prime}$$ where the resistance $R$ is defined as $R=2\overline{h}^{0.5}/C_{v}$.', '[-0.024717083,-0.00690982,-0.013559337,-0.009897472,-0.011339677,-0.014291529,-0.0068867733,0.032879476,0.0066353274,0.036677916,-0.0205578,-0.043474063,0.0045747506,0.014858048,0.015846835,-0.010924306,0.021129003,0.020596506,-0.012048452,-0.029748723,-0.023612427,-0.009678512,-0.04184671,-0.020942874,-0.02191251,0.022219185,-0.0009970788,-0.021333298,0.022839623,0.029814694,0.036204193,0.0340125,-0.049888622,-0.059493627,-0.019139757,0.029141473,-0.014597645,-0.008312068,-0.032456126,0.028361686,0.00060774275,-0.017119631,0.031345513,-0.033095606,0.07795171,-0.0048679877,-0.017865049,-0.046797853,-0.033123784,0.001229895,-0.032045312,-0.055559427,0.06156202,-0.034448758,-0.004906887,0.0057793204,-0.02232331,-0.042512648,-0.04892047,0.047584962,-0.05606887,0.01909822,0.0089106355,-0.04085866,0.02843995,0.040178806,0.010640191,0.0376075,-0.011703416,-0.027291324,0.0042896904,0.038332537,-0.028005634,-0.00397731,-0.07521252,0.04540946,0.049289152,-0.012154354,0.044598512,0.007616526,0.013689049,-0.021805825,0.015973434,0.009022667,-0.037572797,0.0068520214,0.03591861,0.021001427,0.023115907,-0.051238663,-0.014379278,-0.0018852786,0.008278675,-0.03609997,-0.031524647,-0.006307136,-0.015227041,0.03383299,0.026782673,0.01321084,0.024468474,-0.0060328036,-0.03264973,-0.005