INSERT INTO document_chunks VALUES (62, 20, 'This chunk explains the importance of standard process inputs in process control. In process control, analyzing how a process responds to changes in inputs is crucial. Standard types of input changes are used because they are representative of the types of changes that occur in plants and are easy to analyze mathematically. Process inputs fall into two categories: input that can be manipulated to control the process and input that are not manipulated (disturbances).', '[-0.033629604,0.0038263618,-0.065691665,0.026974246,-0.013178685,-0.07017587,-0.0039363857,0.030215075,0.024486192,0.024179948,-0.06468831,-0.029020889,0.012042163,-0.0062348703,-0.0025604467,0.013266919,-0.02205911,-0.0086847935,0.006971419,-0.025971051,-0.0060205464,-0.015396242,0.009466809,-0.013254205,-0.03826707,0.022377772,-0.0036908132,0.0029065688,0.0064192815,0.021396857,0.011532904,0.0012211604,-0.029664343,0.00068949716,-0.01991244,0.0109293405,0.0046692165,-0.050112892,-0.009528036,-0.0028379476,0.008143865,-0.03269998,0.034399487,-0.03810938,0.014163617,0.023336789,-0.028808327,-0.038933806,-0.03984609,-0.00983253,0.002193006,-0.009238481,0.09349692,-0.06523271,-0.0013376051,-0.007930183,-0.042375393,0.027023029,-0.02248097,0.041075498,-0.04887026,0.03520714,0.0073496033,-0.020086559,0.03986075,0.005480488,0.002909501,-0.0046229092,-0.008775028,-0.05149058,0.010299506,0.023629686,-0.01900904,0.014673199,-0.04972605,0.012497094,-0.0052828975,-0.022136375,-0.017610487,0.06049804,-0.036927156,-0.032051392,0.009743031,0.012326256,0.0018827447,-0.004936427,0.05184674,-0.016218295,0.0020615398,0.008821316,-0.009286237,-0.055550184,-0.0006504886,-0.0077056303,-0.038707267,0.030249542,-0.0150394,0.039007038,-0.022757161,0.022315988,0.013418733,0.04599698,-0.009630511,-0.005329617,0.018025205,0.013356949,0.04343029,0.016339026,0.027870474,-0.007984083,0.03429469,0.04576679,0.034069188,0.015655117,-0.029770484,-0.0366854,0.030552516,0.0006527936,0.051522