INSERT INTO document_chunks VALUES (63, 20, 'This chunk describes the characteristics of Step Input. The Step Input is where a sustained and sudden change in a process variable can be approximated by a step change of magnitude, $M$. Mathematically, it is defined as $u_s(t) = 0$ for $t < 0$ and $u_s(t) = M$ for $t \ge 0$. Its Laplace transform is $U_s(s) = \frac{M}{s}$. A special case where $M=1$ is called a unit step change. Industrial application examples of step input include a reactor feedstock suddenly switching from one suppy to another, causing sudden changes in feed concentration, as well as a step change in the electrical heating signal to a stirred tank heater.', '[-0.0018760229,0.0019688543,-0.06740107,0.03685546,0.019071447,-0.029172087,-0.013318242,0.04705715,0.008439913,0.0037339074,-0.012143188,0.013100265,0.01687142,-0.002043724,0.03071496,-0.023522088,0.024986425,0.019698387,0.05832609,0.0005354275,0.0077311173,0.018943988,0.035398114,-0.025427686,-0.0027446288,0.024227165,-0.020454997,-0.005732626,0.024987053,-0.002751005,0.025473125,-0.011930804,-0.036713447,-0.009386859,-0.031260047,0.02529789,-0.009988256,-0.012376523,-0.026045967,-0.001275045,-0.006991053,-0.012743147,0.053069066,-0.031183807,-0.0031236352,-0.009322848,-0.013998677,-0.055443566,-0.008277204,-0.042963054,0.024215274,-0.022872794,0.063258715,-0.040654033,0.00083367334,0.006467697,-0.052904736,0.021492267,-0.07584448,0.025296343,-0.033807516,0.050422903,-0.019034956,-0.0026750336,0.032732435,0.014745082,0.016725888,0.0027375473,-0.0033850211,-0.055549964,-0.0036828981,0.054096963,-0.06259553,0.0011026856,-0.019935882,0.08365973,0.043271672,-0.009877615,-0.023580225,0.035080474,0.0045195953,-0.005568702,-0.030553805,0.008008869,-0.0073375986,-0.028564796,-0.010992858,-0.014554198,0.004611501,-0.003695124,0.051511284,-0.02695307,0.012535323,-0.017678607,-0.03917308,0.0030350715,0.0011527968,0.077863,0.010777835,-0.003389807,-0.018095216,-0.0029341434,-0.02559423,-0.038922217,0.043978