INSERT INTO document_chunks VALUES (64, 20, 'This chunk describes the characteristics of Ramp Input. The Ramp Input is used to approximate "drifting disturbances," which are relatively slow changes that occur up or down over a period of time with an approximately constant rate of change. It is defined as $u_R(t) = at$ for $t \ge 0$, and its Laplace transform is $U_R(s) = \frac{a}{s^2}$. Industrial application examples of ramp-like disturbances include the gradual change in feed composition, fouling of heat exchangers, decay in catalyst activity, or changes in ambient temperature.', '[-0.023381213,0.012721679,-0.037646245,0.029127376,-0.032397553,-0.007434472,0.014237573,0.06566757,-0.015287827,0.021439841,-0.03688776,0.003102224,-0.010111218,0.005015815,0.050299373,-0.015260441,0.008142557,0.022776688,0.038281605,0.011059006,0.033720672,0.024306055,0.0069044367,-0.007839785,-0.00017946324,0.061888944,-0.0358545,0.0126715405,0.031113122,0.03995134,0.004223145,-0.019810809,-0.028087603,-0.021730158,-0.06026448,-0.007970088,-0.0032823454,0.0026331616,-0.030540908,-0.0075295568,-0.047528863,-0.022339858,0.04350817,-0.025284184,0.02107573,0.0023044178,-0.023936171,-0.037706506,0.019632429,-0.025009928,0.002764118,-0.039045442,0.057794403,-0.060066793,-0.027236555,-0.003146789,-0.025573095,-0.022551354,-0.06958757,-0.0102660665,-0.035542153,0.05955735,-0.03315857,-0.031949844,0.019577913,0.041053973,0.021937966,-0.005756977,-0.027871879,-0.05339185,-0.013492414,0.022408713,-0.04034911,-0.017678527,-0.05671561,0.07607598,0.01766355,0.008762114,-0.025974464,0.030333225,0.0017237337,-0.009645877,-0.009517064,0.026703952,-0.008432034,0.02108857,0.0029779787,-0.03246303,0.015642773,-0.026332138,0.0354873,-0.044454258,0.00883149,-0.023126846,-0.058502045,0.005939263,0.023107298,0.018820984,0.045584265,0.016650233,0.024578085,-0.014115468,-0.020526107,-0.030808873,0.046200372,-0.037712574,0.010652647,0.050224714,0.023184566,-0.02917107,0.031832825,-0.01381492,0.027601108,0.01472