INSERT INTO document_chunks VALUES (65, 20, 'This chunk describes the characteristics of Rectangular Pulse Input. The Rectangular Pulse describes a scenario where processes are subjected to a sudden step change and then return to their original value. This behavior is represented by the piecewise function $u_{RP}(t)$, which is defined as $0$ for $t < 0$, $h$ for $0 \le t < t_w$, and $0$ for $t \ge t_w$. In the Laplace domain, this input is expressed as $U_{RP}(s) = \frac{h}{s}[1 - e^{-t_ws}]$. Industrial application examples of  rectangular pulse input include a reactor feed being shut off for one hour or when the fuel gas supply to a furnace is briefly interrupted.', '[-0.034018964,0.040996403,-0.056801584,0.055342212,0.0010034768,-0.0065850294,0.026640888,0.022544574,-0.009966783,0.014425185,-0.020443846,0.018949416,0.03005099,-0.008514471,0.088533744,-0.0058112834,0.031201761,0.019251646,0.073266715,-0.0055481372,0.0037068345,0.044651102,-0.031139921,-0.029517464,-0.017590974,0.03431608,-0.030132992,-0.0009322924,0.0055626906,0.027994655,0.034110703,-0.045164507,-0.035194088,-0.048481263,-0.04855627,0.01186525,-0.012002711,-0.014081365,-0.030864198,-0.006396384,-0.030944895,-0.04567863,0.056852553,-0.018346649,0.0005554496,-0.021783996,0.0058425483,-0.051151063,-0.0020521674,-0.047643665,0.01686074,-0.019668711,0.06360338,-0.041732,-0.028823812,0.0052860025,-0.03605371,0.020176968,-0.07918529,0.01090895,-0.02700913,0.040260185,-0.012478213,-0.020392602,0.010283097,0.050354965,-0.01844062,0.01814831,0.0013475084,-0.026171109,-0.0064920154,0.008281978,-0.03504786,0.005152507,-0.053881783,0.074357316,0.020393511,0.006758676,-0.015814992,0.035436958,0.0029892072,-0.026993493,-0.018547606,0.01752811,0.0073641315,-0.041674573,0.011151781,0.01611831,-0.0049459194,-0.032758206,0.015367252,0.002156127,-0.005337516,-0.019479092,-0.016727116,-0.018269207,-0.0038673047,0.023118863,0.01663965,0.022810547,-0.0037278128,0.020453064,-0.028988486,-0.046062063,0.056933437,0.001282