INSERT INTO document_chunks VALUES (67, 20, 'This chunk describes the characteristics of Sinusoidal Input. The Sinusoidal Input represents periodic or cyclic disturbances and are approximated by the function $u_{sin}(t) = 0$ for $t < 0$ and $A \sin \omega t$ for $t \ge 0$, where $A$ is amplitude, $\omega$ is angular frequency, and $P = 2\pi/\omega$ is the period. Its Laplace transform is $U_{sin}(s) = \frac{A\omega}{s^2 + \omega^2}$. Industrial application examples of sinusoidal input include 24-hour variations in cooling water temperature or 60-Hz electrical noise.', '[-0.021266684,0.01722682,-0.03928111,0.040197834,0.02233253,-0.020460334,0.013027478,0.037885953,0.017667107,0.063593306,0.025675729,0.044215336,0.0072025335,-0.014928507,0.059724387,0.008641834,0.01699739,0.02659622,0.058423556,-0.032486774,0.018160542,0.04137034,-0.026261423,-0.015546888,-0.0139339855,0.04865308,0.0060180905,0.012610489,0.04862627,0.045871146,0.025454227,-0.015688883,-0.0072027813,-0.027968932,-0.028369537,-0.019768715,0.0075336318,-0.021135902,-0.05284503,0.011142435,-0.0037430166,-0.04932375,0.07337658,-0.019157488,0.039493293,-0.019281968,-0.021381594,-0.034905564,-0.0031727303,-0.024845354,0.061057463,-0.03473382,0.060060177,-0.059218127,0.0033948626,-0.01055952,-0.0336918,-0.004939547,-0.08912014,0.003234442,-0.036677286,0.0315457,-0.04061605,-0.033348672,0.016460024,0.006419331,0.023883995,0.012805949,-0.013944309,-0.011100172,0.0016156486,0.054837808,-0.0032016921,0.012918267,-0.049646925,0.0698267,-0.030808656,-0.021614663,-0.046366673,0.06733738,0.010073904,-0.0018695088,-0.02251773,0.019108558,-0.029772962,-0.016676124,0.029377842,0.018890005,-0.0107373325,-0.0066406652,-0.005805864,-0.027879205,0.0026167503,0.007644638,-0.004248807,-0.016755238,0.01608924,0.004348911,0.0320155,0.008807499,0.023954589,-0.0198466,0.01862045,-0.035398617,0.034060907,0.0064798584,0.035333566,0.0027316308,0.0019526074,-0.004419727,0.03932217,0.029764468,-0.0077026305,0.01898476,-0.04880976,-0.