INSERT INTO document_chunks VALUES (68, 21, 'This chunk defines the standard dynamic model for First-Order Processes, introducing the concepts of Process Gain (K) and Time Constant (tau). The standard ordinary differential equation (ODE) for a first-order process is written as $\tau\frac{dy(t)}{dt}+y(t)=Ku(t)$. Taking the Laplace transform yields the standard first-order transfer function $G(s)=\frac{Y(s)}{U(s)}=\frac{K}{\tau s+1}$. The Process Gain ($K$) represents the ultimate value of the response or the new steady state relative to a unit step change in input. The Time Constant ($\tau$) is a measure of the time necessary for the process to adjust to a change in input. A classic physical example is the Stirred Tank Heating process, where $K=\frac{1}{wC}$ and $\tau=\frac{V\rho}{w}$.', '[-0.042115603,-0.003954824,-0.04962336,-0.018359726,0.0052737654,-0.0128929885,0.0025139782,0.029566508,0.011122166,0.037343934,-0.016234733,-0.037281007,-0.00042766405,0.03929191,0.028156267,0.017437117,0.024979005,0.036119536,0.023480771,0.0009959791,-0.013318546,0.021570945,0.01841188,0.003166368,-0.011991828,0.012319817,-0.0009154747,-0.04274779,0.012374263,0.025271408,0.020510202,0.047702204,-0.031823352,-0.05798377,-0.029250722,0.042023834,0.01455031,-0.0006930695,-0.059028104,0.031596746,-0.0019108537,-0.035491988,0.051915083,-0.031046411,0.06655377,0.001336314,-0.0063435724,-0.045655724,-0.0461747,-0.063680224,0.001791584,-0.07592604,0.058785494,-0.020606935,0.018767575,0.017234294,-0.061368812,-0.021410773,-0.07224434,-0.016110586,-0.044441834,0.036668386,0.0032419413,0.013050906,0.011004243,-0.022483045,0.018127212,0.0006074589,0.00034015471,-0.030245688,-0.0030135973,0.042257965,-0.033598077,0.02130384,-0.043722745,0.04394573,0.03243102,-0.0044949567,0.033388063,0.044943493,0.006414685,0.008265356,0.0060789715,-0.03555326,-0.0060675666,0.03966813,0.0024961217,0.004396696,0.030701,-0.02470852,-0.00071045914,-0.054900702,-0.010829363,-0.025867488,0.014318616,-0.06963638,-0.