INSERT INTO document_chunks VALUES (69, 21, 'This chunk derives and analyzes the Step Response of a first-order process, detailing the time-domain solution and key response characteristics. For a step input of magnitude $M$ ($U(s) = M/s$), the output transform is $Y(s) = \frac{KM}{s(\tau s + 1)}$. Applying partial fraction expansion and the inverse Laplace transform yields the time-domain response $y(t) = KM(1 - e^{-t/\tau})$. The step response of a first-order process has specific characteristics: it does not respond instantaneously to a sudden change in its input but follows an exponential curve. At $t=\tau$, the output reaches 63.2% of its final value. At $t=5\tau$, the response is essentially settled (99.3%). The new steady state is $y(\infty) = KM$. A larger time constant $\tau$ implies a slower response speed.', '[-0.0172746,0.016528113,-0.045174226,-0.001495071,0.005851051,0.0074400725,-0.020131797,0.03718191,0.03218867,0.032920074,-0.004784573,0.0024643866,-0.011051602,0.024521815,0.013759756,0.008189247,0.030099673,0.04492202,0.011846291,-0.006200685,-0.00031848182,0.054890163,-0.002207675,0.0014434961,-0.0005940461,0.041347947,-0.043039907,-0.03259211,0.0014779753,0.03763866,0.016386721,0.0048732474,-0.006352892,-0.037844863,-0.011622313,0.046171255,0.01705266,-0.0075355023,-0.05487646,0.03274345,0.0031567658,0.005686629,0.060739744,-0.015839152,0.029767627,-0.006795645,0.016125282,-0.039315153,-0.023822263,-0.07146841,0.040350214,-0.03726842,0.022203779,-0.017118767,-0.006268534,0.015028621,-0.027676951,0.026131522,-0.032237682,0.012685297,-0.024748819,0.047244824,0.046100996,0.034182325,-0.009199586,0.002251506,0.03287967,0.019182084,-0.009538764,-0.016768765,-0.016618162,0.019350473,-0.055074837,-0.00097256014,-0.032991216,0.032536488,0.03408744,0.0029061688,-0.0054276264,0.033492405,0.0061491905,0.004445937,-0.019230463,-0.0041208225,0.017231978,-0.020224836,-0.009396212,-0.0094208885,0.029955331,0.010631602,0.027526017,-0.02948655,-0.00086203637,-0.02