INSERT INTO document_chunks VALUES (71, 21, 'This chunk examines the Ramp Response of First-order processes. For a ramp input defined as $u(t)=at$ in the time domain, taking the Laplace gives $U(s)=a/s^2$, and after applying partial fraction expansion, the response is derived as $y(t) = Ka\tau(e^{-t/\tau} - 1) + Kat$. For large values of time ($t \gg \tau$), the exponential term decays, and the response simplifies to $y(t) \approx Ka(t - \tau)$. This indicates that the output tracks the ramp input but with a constant time delay equal to the time constant $\tau$. The term $Ka\tau$ represents the dynamic error between the scaled input and the output.', '[-0.016048681,0.026508547,-0.036302943,-0.0014947329,-0.011599605,-0.034105025,0.013605598,0.04994015,-0.00086552254,0.019927574,-0.0071557052,0.009932853,-0.017551856,0.045400646,0.0036366114,0.004665794,0.042742513,0.047390524,0.0069637727,0.014273634,0.014088647,0.01797267,-0.02676305,-0.0056640925,-0.0015903519,0.04079868,-0.031109992,-0.006894938,0.006913726,0.018371714,0.016478933,-0.0012210741,-0.037384104,-0.05233215,-0.02913169,0.004828141,-0.018602312,0.005979014,-0.03764769,0.023816831,-0.05055774,-0.02241376,0.073540874,-0.013482715,0.04145568,0.00046979566,0.003040164,-0.05175146,-0.026939211,-0.03681439,0.013157636,-0.04063665,0.023549257,-0.023058418,-0.023457117,0.0023547264,-0.03673538,-0.016787874,-0.07718137,0.0013999455,-0.008290892,0.023548333,0.0063680545,-0.02509333,0.011321016,0.019917661,0.042860806,0.016793955,-0.0037533178,-0.014264418,-0.0068306117,0.021847958,-0.07057959,-0.017246654,-0.03590866,0.034511905,0.06550188,0.038263265,-0.025798019,0.05803232,0.016732283,0.0057520955,-0.026473409,-0.0029038726,-6.3353786e-05,0.011013728,-0.016609391,-0.023979068,0.017390998,-0.003966312,0.041119985,-0.021095166,-0.0124383755,0.006294612,0.014782939,-0.029639624,-0.03926556,0.0428296,0.05118154,-0.00437519,0.031202076,-0.011779196,0.009245912,0.004484562,0.05029123,-0.034711495,-0.013653115,0.0321