INSERT INTO document_chunks VALUES (73, 22, 'This chunk describes the dynamic behavior of integrating processes, using a liquid storage tank with a constant-speed pump on the outflow line to illustrate models characterized by a $1/s$ term and a lack of steady-state gain. Considering a tank with a pump attached to the outflow line, the mass balance is expressed as $\frac{d(\rho V)}{dt} = \rho q_{i} - \rho q$. Assuming constant density and a constant cross-sectional area $A$, the Laplace transform yields $AsH^{\prime}(s) = Q_{i}^{\prime}(s)$, which results in the transfer function $\frac{H^{\prime}(s)}{Q_{i}^{\prime}(s)} = \frac{1}{As}$. Integrating models are characterized by the term $1/s$ and do not possess a steady-state gain.', '[-0.011488123,0.0013761935,-0.0378727,0.033271156,-0.020716516,-0.037794452,0.0008622354,0.042085215,0.0016691638,0.03536386,-0.0076453807,0.010039768,0.0013161943,0.029798618,0.018478364,0.01852223,0.0065486426,0.033456273,0.021748936,-0.018541856,-0.0005627053,-0.00024220244,0.026001923,-0.014110479,0.003465854,0.046477497,-0.011065551,-0.028926712,0.024981238,0.055520054,0.024718665,0.02617078,-0.061811592,-0.03270563,-0.0078149745,0.035775267,-0.019854913,-0.01825063,-0.04751682,0.056177635,-0.011791082,-0.019778362,-0.005362698,-0.026662163,0.07587888,-0.008663643,-0.019479569,-0.05596772,-0.040925507,0.021011882,0.01779671,-0.055060063,0.030123197,-0.020017192,0.02597317,-0.01074378,-0.0831942,-0.028346062,-0.052462433,0.009519288,-0.04103001,0.06673144,-0.015495886,0.0021530897,0.020799667,0.049702786,0.017971987,0.029705519,-0.0037016075,-0.05180503,0.004838563,0.034492828,-0.019030951,-0.018792152,-0.047000427,0.044632375,0.043476,-0.036473926,0.026310349,0.029435476,0.016968915,-0.030919591,0.004288516,-0.0039717997,-0.053951547,0.0039082584,0.013007935,-0.034098357,0.036342714,-0.03565904,-0.010744019,-0.0130503345,-0.000669914,-0.03453281,-0.037758473,-0.0026609276,-0.0067695384,0.039229948,0.020006036,-0.008438463,0.027752113