INSERT INTO document_chunks VALUES (75, 23, 'This chunk defines the three adjustable parameters of a second-order transfer function: the static gain, the time constant, and the damping factor, which determines oscillatory behavior. The second-order transfer function is characterized by three adjustable parameters. The static gain $K$ and the time constant $\tau$ are conceptually the same as in first-order processes. The damping factor $\zeta$ (zeta) is a critical parameter that determines whether the system exhibits oscillatory behavior.When comparing the series form $(\tau_{1}s+1)(\tau_{2}s+1)$ with the standard second-order denominator $\tau^{2}s^{2}+2\zeta\tau s+1$, the parameters can be related as $\tau=\sqrt{\tau_{1}\tau_{2}}$ and $\zeta=\frac{\tau_{1}+\tau_{2}}{2\sqrt{\tau_{1}\tau_{2}}}$.', '[-0.052751172,-0.018183636,-0.05151353,0.0348405,-0.009055026,-0.036790248,-0.004897212,0.016808009,0.02777607,0.039813276,-0.01874376,-0.025117567,-0.016400635,0.00041762984,0.024319204,0.0309214,-0.0051243976,-0.008324266,-0.0124306,-0.009310261,-0.04449384,-0.009618289,-0.012184007,0.002930923,-0.031530585,0.00813555,-0.02667625,-0.037303746,0.018572701,0.07821102,-0.013554782,0.026042987,-0.032641176,-0.06024075,-0.042347994,0.0152085,-0.01117644,-0.022781901,-0.04145109,0.06551561,-0.02835894,-0.029791757,-0.011892625,-0.010559233,0.099901274,0.006739704,-0.0018615177,-0.058815014,-0.026694167,-0.026175788,-0.0367018,-0.036101606,0.06698852,-0.04234854,0.047302123,0.017054377,-0.06316891,-0.0008585308,-0.05163991,0.013021693,-0.0050264415,0.037910037,0.033993434,-0.0028298993,-0.0048216665,0.0034747282,0.011901322,-0.015538477,-0.010077511,-0.0014831069,0.025544552,0.06373345,-0.0061554946,0.004359295,-0.027347723,0.036079556,-0.023382632,0.00717399,-0.02125852,0.0070468243,-0.008799576,-0.0037158825,0.04183002,-0.00089522684,-0.0237127,0.040715046,0.040162887,0.010413744,0.017295038,-0.042987026,0.0018774939,-0.046666473,-0.01435527,0.005971919,0.0069193323,-0.023529