INSERT INTO document_chunks VALUES (85, 25, 'This chunk analyzes the impact of a single real pole on system stability, contrasting the bounded response of negative poles with the unbounded response of positive poles. Consider a system with a single real pole represented by $G_{1}(s)=\frac{a}{s-\alpha}$ where $\alpha\ne0$. The inverse Laplace transform yields the time-domain response $g_{1}(t)=ae^{\alpha t}$. As time increases, the behavior of the system depends entirely on the sign of the pole $\alpha$. If $\alpha < 0$, the exponential term decays toward zero and the response remains bounded, indicating a stable system. If $\alpha > 0$, the exponential term grows indefinitely and the response becomes unbounded, meaning the system is unstable.', '[-0.057580706,0.03094944,-0.012111484,-0.0020382793,-0.020632157,-0.06866063,0.0048826407,0.063017815,-0.008694185,0.0033989209,-0.036982894,0.020210274,-0.02650924,-0.0126557285,0.0059293597,0.03189677,0.0346253,0.0051580304,0.010154761,-0.007043067,-0.027081154,0.0041764555,-0.022373984,-0.013965121,0.010053595,0.031882815,-0.0124693625,0.013314924,0.006105419,0.081314266,-0.026847074,0.01293108,0.005772932,0.0071992804,-0.025484605,0.027996235,0.0065849517,-0.05732214,-0.026701648,-0.007951369,-0.012820766,-0.041365623,0.02739561,-0.013656448,0.0032148114,-0.02063408,-0.019359497,-0.047404416,-0.022659756,-0.04063109,0.024305739,-0.026295012,0.07138624,0.030420557,-0.06066222,0.0059323586,0.0038025926,-0.014986016,-0.063265145,-0.006211485,-0.01723092,0.032711823,-0.041548997,-0.014901483,-0.011622592,0.028566347,0.008840143,0.046226516,-0.017390614,-0.06983382,0.00432606,0.027417026,-0.025524039,-0.01613614,-0.041744307,0.054305878,0.013435124,0.010756159,0.0073754587,-0.0023012466,0.021536415,-0.022474809,-0.018086754,-0.008715333,0.022555338,0.026362654,0.013758814,-0.0067789718,-0.0334614,-0.014816242,-0.009309427,0.0007453966,0.024927378,-0.012533684,-0.04102717,-0.028192623,-0.025415033,0.0024445665,0.034274388,0.02