INSERT INTO document_chunks VALUES (77, 23, 'This chunk provides the time-domain step response equations for the three distinct cases of a second-order process: overdamped, critically damped and underdamped. For a step change of magnitude $M$, the output in the s-domain is $Y(s)=\frac{KM}{s(\tau^{2}s^{2}+2\zeta\tau s+1)}$. In the overdamped case where $\zeta > 1$, the time-domain response is given by $y(t)=KM(1-\frac{\tau_{1}e^{-t/\tau_{1}}-\tau_{2}e^{-t/\tau_{2}}}{\tau_{1}-\tau_{2}})$, where the effective time constants are $\tau_{1}=\frac{\tau}{\zeta-\sqrt{\zeta^{2}-1}}$ and $\tau_{2}=\frac{\tau}{\zeta+\sqrt{\zeta^{2}-1}}$. In the critically damped case where $\zeta = 1$, the response is expressed as $y(t)=KM[1-(1+\frac{t}{\tau})e^{-t/\tau}]$. In the underdamped case where $0 \le \zeta < 1$, the time-domain response to a step input is oscillatory and defined by the equation $y(t)=KM[1-e^{-\zeta t/\tau}(\cos(\sqrt{1-\zeta^{2}}\frac{t}{\tau})+\frac{\zeta}{\sqrt{1-\zeta^{2}}}\sin(\sqrt{1-\zeta^{2}}\frac{t}{\tau}))]$.', '[-0.0076652025,-0.006067684,-0.024803257,0.0026202213,0.016614204,-0.025388917,-0.0052306675,0.019776162,-0.0005151046,0.032021776,-0.0015649493,0.022749992,-0.016540105,-0.0014992353,0.02191581,0.022220688,-0.0025377218,0.06035921,0.008011639,-0.009978992,-0.013818674,0.024852855,0.020384276,0.0033151938,-0.047304127,0.032108206,-0.0013494726,-0.02953071,0.0024171027,0.012083052,0.002327094,0.0048739617,0.0037020182,-0.040946435,-0.025715621,0.024490478,0.010043078,-0.0025422678,-0.057869934,0.017765386,-0.009198083,-0.039044242,0.05806328,-0.040267948,0.047881898,0.023003627,0.001177536,-0.070741065,-0.015218454,-0.056027725,0.0049562575,-0.029148242,0.036454108,-0.023400264,0.026280023,0.026236648,-0.033954795,-0.003031512,-0.08063708,0.04057072,-0.0061947536,0.04905933,0.03503287,0.042771805,-0.011832144,0.012943453,0.062072005,-0.0051241606,-0.023722844,0.0074697584,-0.019617219,0.0026748425,-0.0043646907,-0.029744592,-0.0047372277,0.029551148,0.