INSERT INTO document_chunks VALUES (78, 23, 'This chunk summarizes the general behavior of second-order processes in response to a step input, highlighting how the damping factor and time constant affect the speed and nature of the response. In summary, the output of a second-order process eventually (asymptotically) reaches a new steady state at $KM$ following a step change in input. Increasing the damping factor $\zeta$ or the time constant $\tau$ makes the response more sluggish. Oscillations and overshoot are observed specifically when $\zeta < 1$ (the underdamped case). The fastest response without oscillations and overshoot occurs when the system is critically damped at $\zeta = 1$.', '[-0.040410616,-0.027385656,-0.04424056,0.005291595,-0.012583387,-0.045447815,-0.013312676,0.02443822,0.020458108,0.03772004,-0.0065030744,-0.02551721,0.017863372,-0.009793587,0.0034777583,-0.022369927,-0.019860258,0.0151540795,-0.011025348,0.0075172526,-0.007033945,0.008466769,0.0104990015,-0.015607819,-0.020670896,0.016623333,-0.04210119,-0.010394525,0.007669806,0.053127576,0.01213391,0.04380848,-0.02737129,-0.04780463,-0.014995633,0.013160202,0.009428454,-0.067189686,-0.03568613,0.03479562,-0.026166312,-0.014134712,0.020566821,-0.011389218,0.066522785,0.022050053,-0.0039007463,-0.052687246,-0.019865504,-0.050508507,-0.014052724,-0.018705094,0.050235093,-0.02477003,0.030468155,0.036201335,-0.018036813,0.009329943,-0.04067166,0.034642916,-0.0171936,0.039592065,0.059763163,-0.011761057,-0.013479624,0.05252479,0.029514125,-0.0042176195,-0.022943655,-0.01644977,0.018632581,0.046103608,-0.005465101,-0.01700118,-0.010530672,0.04888201,0.0018598703,-0.001378767,-0.022023933,0.026902957,-0.0026005819,-0.024703968,0.010733548,-0.0016606366,-0.018550452,0.00938655,0.0065617957,-0.0070553604,0.026497534,-0.0065472,0.027159417,-0.046062164,-0.0014205818,-0.008877473,0.016550768,-0.006587387,0.0012359744,0.020633144,0.05356949,0.0029799577,0.0025033108,-0.0014835382,0.009798618,-0.021627232