INSERT INTO document_chunks VALUES (79, 23, 'This chunk explains the importance of studying underdamped systems. While very few chemical processes encountered in chemical industries exhibit natural (when control is not applied) underdamped behavior, feedback controllers may cause the closed-loop systems to exhibit underdamped dynamics. Control engineers often attempt to make the response of the controlled variable to a set point change approximate the ideal step response of an underdamped second-order system, that is, make it exhibit a prescribed amount of overshoot and oscillation.', '[-0.099126264,-0.0062872977,-0.030113572,-0.0130492365,-0.036953304,-0.045896113,-0.021941409,0.009925916,-0.020817067,0.042274393,-0.034158655,-0.030578092,0.014801166,0.0076668886,-0.018688727,-0.007718551,-0.015780203,-0.018969366,-0.015789267,-0.008328461,-0.02284428,0.005140477,0.042471122,-0.024492437,-0.02720293,0.018726582,-0.064259976,-0.0077256123,-0.045759607,0.00037304492,0.015428532,0.0007952111,-0.0030624722,0.018496647,-0.0019645116,-0.006233531,0.0273104,-0.072444834,-0.013210538,0.021851787,0.002454611,-0.04792001,0.022807391,-0.042442843,0.02346432,-0.009723227,-0.008923993,-0.018233648,-0.008345738,-0.040241186,-0.013722826,-0.014990912,0.027778968,-0.010640442,-0.02272885,0.037519764,-0.045429118,-0.027387753,-0.041283395,0.045970745,-0.032268517,0.019373473,0.022276904,-0.012562459,0.03337181,0.05838431,0.008921352,0.011005321,-0.020109227,-0.027092008,0.034957536,0.042494547,-0.010418113,-0.022569912,-0.016163802,0.05207367,-0.03065353,-0.026957557,-0.0028667036,0.04680017,-0.021606866,-0.0070653264,0.03375895,0.012855455,0.018464865,0.020840304,-0.009445547,0.0023629125,-0.0054317117,-0.01982393,0.01657573,0.0083393315,0.03319794,-0.00010890863,-0.0025512206,0.031278346,0.016700534,0.025916193,0.017256442,0.010583765,0.006273729,0.007298808,-0.013326173,-0.021682773,0.024223745,-0.0290024,0.028614452,0.029991157,0.03828906,0.0039021024,0.034131862,0.020569006,0.