INSERT INTO document_chunks VALUES (80, 23, 'This chunk defines the response characteristics of an underdamped second-order systems. The performance of underdamped systems is characterized by several specific metrics. The rise time $t_{r}$ is defined as the time when the output "first" reaches the new steady-state value. The time to first peak $t_{p}$ is the time required for the output to reach its first maximum value and is calculated as $t_{p}=\frac{\pi\tau}{\sqrt{1-\zeta^{2}}}$. The settling time $t_{s}$ is the time required for the output to reach and remain within a band of $\pm 5\%$ of the total change in the output variable. Overshoot is defined by the ratio $a/b$, where $a$ is the height of the first peak above the steady state and $b$ is the total steady-state change; the formula is expressed as $a/b = \exp(\frac{-\pi\zeta}{\sqrt{1-\zeta^{2}}})$. The decay ratio is the ratio of the heights of successive peaks, $c/a$, and is given by $\exp(\frac{-2\pi\zeta}{\sqrt{1-\zeta^{2}}})$ or $(a/b)^2$. The period of oscillation $P$ is the time between two successive peaks or valleys and is defined as $P=\frac{2\pi\tau}{\sqrt{1-\zeta^{2}}}$.', '[-0.029370707,-0.013631929,-0.048232354,0.04470735,-0.0026119098,-0.0050313263,0.013606144,0.05317705,-0.0073192813,0.05070632,-0.030580528,0.0014486124,-0.01846008,0.002540008,0.04408504,0.004111228,0.0020454,0.011914377,0.01276131,0.015530999,-0.0025485195,0.011714812,0.017463287,0.030399986,-0.036477093,0.03363894,-0.020856025,-0.013064259,0.018869149,0.062403623,0.0032719143,-0.014246836,0.013922644,-0.038812365,-0.0300124,0.011328241,-0.006064197,-0.036002647,-0.039561104,0.06882632,0.0017221905,-0.00653867,0.012797384,-0.04123555,0.06570043,-2.3894123e-05,0.0018047731,-0.0484475,-0.026621504,-0.05059016,0.008727174,-0.009625761,0.03428914,-0.014456891,-0.001555674,0.027176203,-0.049904495,-0.01189708,-0.06340566,0.025044205,-0.024722803,0.08109645,-0.021150913,-0.0031062448,-0.008140314,0.017632546,0.04737452,0.010185335,