INSERT INTO document_chunks VALUES (81, 24, 'This chunk introduces the definition of stability and system stability in process control. An intuitive definition of stability is that the process output must remain bounded in response to all bounded inputs. This implies that if all the inputs acting on the system do not grow to infinity, the resulting response should likewise stay within a defined range rather than diverging. If a system is stable, the response must be bounded for all bounded inputs. Since checking the response for every possible different bounded input is impossible, engineers rely on the fact that the response of a linear system is bounded for all bounded inputs if the response is bounded for a unit impulse change in input. This impulse response would approach zero asymptotically.', '[-0.018048678,0.015563578,-0.046423912,0.020390237,0.0042965384,-0.066178024,-0.0043096957,0.024909195,0.042393833,0.018660361,-0.030374043,-0.009432134,0.012556489,-0.005586649,0.01081114,0.028221115,0.021362768,-0.025555814,0.004172955,-0.034942985,0.01861291,-0.012795432,0.011295537,-0.04201141,-0.01230896,0.015016501,0.011385031,0.006938271,-0.0113998335,0.052914154,0.017203948,0.010004747,-0.019017143,0.007833027,0.008208636,0.035689447,-0.0034027328,-0.05661024,-0.0045828214,0.015246524,-0.015200261,-0.008166252,0.013174658,-0.049367048,0.0352364,-0.017697746,-0.0097671375,-0.04516325,-0.076881334,-0.016816963,0.0058763777,-0.023521034,0.045343094,-0.017947128,-0.008832268,0.032725934,-0.017604714,0.036784925,-0.017887276,0.0467562,-0.06326584,0.034651756,-0.015655443,-0.020722382,0.03975015,-0.01869608,0.028324088,-0.00042525947,-0.0042171613,-0.04337418,0.021123927,0.037718132,-0.076365784,0.03241556,-0.050983254,0.060673274,0.02129845,-0.013299213,-0.016625986,0.014364326,-0.026173064,-0.023471233,-0.0031242466,0.007896084,-0.004848899,-0.03209423,-0.005749846,-0.009665649,0.018228812,-0.00976064,0.021360243,-0.039457884,0.017641734,-0.032781847,-0.062053468,-0.