INSERT INTO document_chunks VALUES (82, 24, 'This chunk provides a mathematical example of stability analysis for a specific transfer function and introduces the concept that pole locations determine linear system stability. Consider a process defined by the transfer function $G(s)=\frac{Y(s)}{U(s)}=\frac{1}{s+10}$. For a unit impulse change where $U(s)=1$, the output in the s-domain is $Y(s)=\frac{1}{s+10}$. Inverting this to the time domain yields $y(t)=e^{-10t}$. Because this exponential function decays to zero, the system, or $G(s)$ is stable. While simulating responses for unit impulse changes makes stability analysis tractable, the stability of linear systems depends fundamentally on the location of the poles of the transfer function.', '[-0.045452964,-0.0064040595,-0.06873289,0.045774218,0.03305007,-0.07066599,-0.0026815347,0.044996623,0.019002957,0.011366401,-0.026414312,0.008247914,-0.0006116826,0.007627094,0.017209379,0.033123598,0.032916866,0.01521448,0.012853926,-0.021129956,-0.009076568,-0.03145901,0.017442495,-0.04326888,-0.012004318,0.036101587,-0.0074757896,0.008980582,0.012811054,0.06905363,0.013438464,0.033557642,0.0055964272,-0.004075142,-0.048525598,0.029864373,-0.023763621,-0.02766004,-0.037237193,0.04948334,-0.008134201,-0.042227603,0.009800532,-0.04383298,0.011271559,-0.012182975,0.011489966,-0.04496869,-0.061750524,-0.018321732,0.00041281112,-0.024000501,0.050657436,-0.005152811,0.0022102713,0.025693975,-0.019424904,-0.0009629397,-0.014009523,0.035088375,-0.03299578,0.048107047,-0.022097992,0.0022727419,0.03711163,0.00762786,-0.00534775,0.021176878,-0.010795105,-0.037449155,0.03706798,0.030061703,-0.036215026,0.030406494,-0.030193426,0.047215473,0.010571942,-0.034248587,0.03217151,-0.0037870896,-0.010763056,-0.007685375,-0.012716402,-0.008026244,-0.038859777,0.014543167,0.026272418,0.005036127,0.016956208,-0.056369927,-0.012669942,0.0016268082,0.021213552,-0.0045654094,-0.06328326,-0.013119183,-0.037681513,0.010644506,0.032543506,0.011536715,