INSERT INTO document_chunks VALUES (83, 25, 'This chunk defines poles and zeros, and how their numeric values describe the dynamic behaviour of a transfer function model. The dynamic behavior of a transfer function model $G(s)=\frac{b_{0}s^{m}+...+b_{m}}{a_{0}s^{n}+....+a_{n}}=\frac{Z(s)}{P(s)}$ is characterized by the numerical value of its poles and zeros. Poles are defined as the roots of the denominator polynomial $P(s)$, which is also referred to as the characteristic polynomial. Zeros are the roots of the numerator polynomial $Z(s)$ and represent the numerator dynamics of the process.', '[-0.040667877,-0.049839072,-0.049349844,0.04118124,0.0120977,-0.055084802,0.0051173014,0.021853363,-0.019975523,0.01582617,-0.042200748,0.024051001,-0.006049288,0.0012897478,0.041569527,0.025147585,-0.0044137263,-0.02769267,0.03020037,-0.020082874,0.013669806,0.0149254,-0.0426438,-0.0015774727,-0.0027619665,0.0181262,-0.012334071,-0.0048357714,-0.00085820217,0.07043528,0.009231387,0.0061735795,0.017108457,-0.007433735,-0.044716004,0.03724367,-0.028447062,-0.030790063,-0.036645737,-8.156349e-05,-0.021595933,-0.03305105,0.010429157,-0.06529802,0.019930683,0.015181295,-0.00455565,-0.05577506,-0.05281638,-0.039389424,-0.0074431277,-0.029177617,0.04450212,0.0042503607,0.000927497,0.06507727,-0.06743169,-0.02109979,-0.06348318,0.0288673,-0.009427098,0.054128654,-0.019163502,0.01828988,-0.003570978,0.014750922,-0.014629617,0.009152102,-0.024121776,-0.025706057,0.03367102,0.051789112,-0.009953689,0.0027561386,-0.029450152,0.061279614,-0.019840725,-0.035206642,-0.0010787789,0.005397311,0.0037081316,-0.035269424,-0.017823476,-0.039386954,-0.0058853296,0.03746311,0.02656059,0.048745167,-0.012703264,-0.026030917,-0.012967701,-0.017108731,0.017036801,-0.05540309,-0.063460484,-0.022404699,-0.05248473,0.0046721543,0.007415041,0.03801127,0.017800191,0.03624585,-0.011114555,-0.018223109,0.028470406,-0.01604915,-0.024322644,-0.0023060024,0.0042737178,-0.053026166,0.021287614,-0.02233248,0.01295