INSERT INTO document_chunks VALUES (84, 25, 'This chunk explains the central idea of system stability by analyzing the partial fraction expansion of a system''s unit impulse response. For a unit impulse input where $U(s)=1$, the output response in the s-domain is equal to the transfer function, $Y(s)=G(s)$. To determine system stability, one considers the partial fraction expansion of $Y(s)$, which may contain terms for real poles, complex poles, and repeated real poles. A system is considered stable if its time-domain response $y(t)$, calculated as the inverse Laplace transform of $Y(s)$, remains bounded as time increases. This condition is met if each individual term in the expansion results in a finite contribution.', '[-0.033496145,0.017538015,-0.045845136,0.039400745,0.00034557868,-0.061506014,0.026123207,0.024528181,0.015965428,0.03451874,-0.030073756,0.023014188,-0.042100046,0.028718816,0.013851186,0.015795376,0.028265769,0.03347183,0.024409644,-0.018730896,-0.0007297273,-0.027419934,0.010784132,-0.003124378,-0.008416535,0.043068055,-0.03191661,0.014281026,0.024816344,0.08990886,0.015829138,0.013199649,-0.016742196,-0.014258539,-0.010720229,0.030425387,-0.016206209,-0.055239804,-0.037193194,0.041143585,-0.027479488,-0.03181407,0.02160192,-0.026277717,0.037880845,-0.04143634,0.00715332,-0.042142432,-0.03528165,-0.024102319,0.021644974,-0.008022016,0.05579232,0.0015927508,-0.017449861,0.01773938,-0.012699586,0.0050589344,-0.030804766,0.01411853,-0.009027864,0.042428844,-0.02970066,0.011509247,0.020753928,-0.0019261496,0.042923592,0.038229972,-0.00845752,-0.054778785,0.02544161,-0.0037558149,-0.047247063,0.007826648,-0.030233767,0.046059772,0.035908543,-0.032405235,0.011774503,0.022710565,-0.01221694,-0.003529451,-0.0143947955,0.005581885,-0.02977962,0.0022097817,0.027754871,0.006578773,0.024921177,-0.040536404,-0.0033334002,-0.015233371,0.02909666,-0.0074230083,-0.013093926,-0.009290091,-0.0020359897,0.03565402,0.050085653,0.0013429642,0.022971058,-0.016651914,