INSERT INTO document_chunks VALUES (87, 25, 'This chunk explains how complex poles affect system stability and oscillations, focusing on the significance of the real part of the pole. For a system with complex conjugate poles $G_{2}(s)=\frac{bs+c}{(s-\beta-j\gamma)(s-\beta+j\gamma)}$, the inverse Laplace transform results in a time-domain response $g_{2}(t)=e^{\beta t}(b \cos(\gamma t)+\frac{c+\beta b}{\gamma} \sin(\gamma t))$. While the sine and cosine terms cause oscillatory behavior, their contribution is always finite. Therefore, the stability of the system depends on the exponential term $e^{\beta t}$. If the real part of the complex poles $\beta$ is negative, the oscillations will decay over time. If $\beta$ is positive, the oscillations will grow indefinitely, resulting in an unstable system.', '[-0.057041235,0.022658676,-0.022038447,0.025742296,0.010328078,-0.0749959,0.0062489016,0.040402498,-0.018570077,0.01792695,-0.02904418,0.026781572,-0.03236113,0.01045869,-0.008518796,0.016360322,0.032163348,0.002376823,0.011740824,-0.016444271,-0.038993157,-0.016531738,-0.0634989,-0.020387629,-0.016351826,0.012623249,-0.0034754283,0.036183048,-0.011936559,0.059184026,-0.046976957,0.025910497,-0.019721065,-0.007910642,-0.055137485,-0.0073169,0.0069673103,-0.053464405,-0.021910435,0.0093123065,-0.004656367,-0.03334309,0.06204567,-0.021108929,0.008117861,-0.041113596,-0.05193948,-0.04554506,-0.0029622742,-0.020907022,0.008321646,-0.035308577,0.07809399,-0.0039981618,-0.02797939,0.007423688,-0.019602718,-0.0098642185,-0.064365186,-0.012765727,0.00030376724,0.031850938,-0.0097424025,-0.009319785,-0.02008528,0.022786489,0.010943774,0.041893944,-0.012167916,-0.06282495,-0.0073390594,0.037207693,-0.008206962,-0.010920605,-0.016943067,0.038479134,0.0022118576,-0.0117901815,-0.019254766,0.017551737,3.823954e-05,-0.03716596,-0.014657381,-0.0023578866,-0.02522436,0.03602784,0.021454426,0.0045295837,-0.031094875,-0.0045215683,-0.0052661593,-0.0121423025,0.025878932,0.009451964,-0.