INSERT INTO document_chunks VALUES (88, 25, 'This chunk details the behavior of systems with pure imaginary poles, which result in sustained oscillations and marginal stability. When a system has pure imaginary poles, the real part $\beta$ is equal to zero. In this case, the time-domain response becomes $g_{2}(t)=b \cos(\gamma t)+\frac{c}{\gamma} \sin(\gamma t)$. The response $g_{2}(t)$ does not grow with time but shows sustained oscillations that never decay. Systems with pure imaginary poles lie on the boundary of stability and are classified as marginally or critically stable systems.', '[-0.067721225,0.011343242,0.014882417,0.016043227,-0.003833978,-0.057458203,0.015644781,0.044376075,0.0017634928,0.021657709,-0.03392493,0.003110335,-0.030577097,0.0035088542,-0.011387838,0.025743065,0.010089563,0.0073070796,-0.0070628677,-0.03540249,-0.047829438,-0.022934897,-0.025494043,-0.0030807513,-0.0020336644,0.021913266,-0.018430302,0.039360166,-0.0032759188,0.106747486,-0.019847302,0.03815141,-0.00027405366,-0.039480574,-0.012080774,0.016088247,-0.021290272,-0.0443992,-0.026045075,0.03907876,0.011489489,-0.03185939,0.033557586,-0.0024058032,0.00031089652,-0.029380964,-0.034528196,-0.04641802,-0.013735147,-0.03215591,-0.00070137467,-0.01095348,0.033486284,-0.008676859,-0.022785865,0.063062124,-0.017851472,-0.000751466,-0.047169622,0.040884905,-0.018335765,0.044041403,-0.029789593,-0.024239266,-0.02430822,0.002081839,0.024460008,0.031397667,-0.020358965,-0.044923622,-0.022461249,0.013476639,0.010579977,-0.011719009,-0.0142738605,0.023735225,0.00355252,-0.013646409,-0.0108049745,-0.0065250695,-0.0101659745,-0.03396867,-0.021515956,0.025962198,-0.037038963,0.05990583,-0.009105751,0.04568528,-0.0019759461,-0.021064412,-0.030382233,-0.018805515,0.04358909,-0.04726255,-0.055975784,0.012138257,0.01685342,-0.003072928,0.029781684,0.03536739,0.0387905,-0.029811798,-0.012718068,-0.03730684,0.028049642,0.0132722445,-0.014185204,0.031030662,-0.01369888,0.0114218015,0.044055477,0.0352