INSERT INTO document_chunks VALUES (89, 25, 'This chunk examines the stability criteria for systems with repeated real poles. A system with repeated real poles of order $r$ is represented by $G_{3}(s)=\frac{d_{1}}{(s-\eta)}+\frac{d_{2}}{(s-\eta)^{2}}+....+\frac{d_{r}}{(s-\eta)^{r}}$. The inverse Laplace transform is $g_{3}(t)=e^{\eta t}(d_{1}+d_{2}t+\frac{d_{3}t^{2}}{2!}+...+\frac{d_{r}t^{r-1}}{(r-1)!})$. If $\eta \ge 0$, the response $g_{3}(t)$ becomes unbounded as time increases because the exponential or the polynomial terms grow with time. If $\eta < 0$, the response remains bounded because the exponential term $e^{\eta t}$ decays faster than the polynomial terms grow. These conclusions are consistent with those obtained for non-repeated poles.', '[-0.033179488,0.022693718,-0.005077653,0.008739045,-0.0078198835,-0.055015404,0.027742524,0.03966859,-0.03799382,-0.0074629947,-0.03150654,0.025187697,-0.034423176,0.0103437295,0.008031518,-0.001056882,0.021973493,-0.00972416,0.018189723,-0.010470195,-0.037121776,-0.014125368,-0.03171596,-0.015474488,-0.017204821,0.018070288,0.006106765,0.0062535615,0.0027464763,0.07417543,-0.030436262,0.005566648,0.022930117,-0.008049966,-0.0012607818,-0.003132156,0.009248078,-0.048750453,-0.030830191,0.03110495,-0.018541751,-0.009986108,0.039190955,-0.011758443,0.005004516,-0.016697923,-0.039004218,-0.04633209,0.0002946674,-0.03790085,0.0050962437,-0.0316343,0.05263888,0.011649506,-0.038330052,0.031597946,-0.032327503,-2.9656972e-05,-0.062443275,0.011198567,-0.02497231,0.054258626,-0.06326976,0.00059588323,-0.008208614,0.038410977,0.036044925,0.027122239,-0.007878935,-0.038606007,-0.011156637,0.031669192,-0.04121645,0.0036092733,-0.066445716,0.04865746,0.005947218,0.012758252,-0.021128766,0.0076417834,0.0018738954,-0.030367833,-0.03336417,0.030357132,-0.043982908,0.05049081,-0.0026459515,-0.010696694,-0.01311256,-0.044623278,-0.007806423,0.0018071854,-6.817294e-05,-0.007187846,-0.03998766,-0.014482436,-0.010750164,0.008216505,0.02422