INSERT INTO document_chunks VALUES (93, 26, 'This chunk explains the specific theoretical impact of zeros on a system''s response. The presence or absence of zeros has no effect on the number and location of the poles and their associated response modes, unless there is an exact cancellation of a pole by a zero with the same numerical value. However, the zeros exert a profound effect on the coefficients of the response modes which are found by partial fraction expansion. Consequently, zeros do not change the underlying exponential decay or oscillation frequencies determined by the poles, but they do change the magnitude and sign of these components in the final time-domain solution.', '[-0.0073176045,-0.0080726035,-0.05380084,0.0258108,-0.024932379,-0.05584709,0.053893793,0.042357493,0.0034116034,-0.015482522,-0.029481987,-0.015387719,-0.030024434,-0.019892594,-0.03405767,-0.009205803,-0.0038368257,-0.017499551,-0.026476717,0.0050516883,-0.04532699,0.0037344468,-0.02468505,0.0066351555,0.057489038,0.02299638,-0.052703954,0.015602167,-0.014381293,0.05132488,-0.01643505,0.007241337,0.02269454,-0.0050695282,-0.020667732,0.021476304,0.01310912,-0.05487157,-0.016166277,-0.012156272,-0.0038251423,-0.024527235,-0.0010100403,-0.015425709,0.011305894,-0.018906465,-0.055834636,-0.052450325,-0.015814707,-0.042738106,0.0035548485,-0.02589136,0.07283929,-0.011081823,-0.029372178,0.040756118,-0.039335098,-0.014037346,-0.043985974,-0.016786374,-0.003607549,0.023195803,-0.00572492,-0.03319687,-0.0139013985,0.013393068,-0.019617988,0.0097488295,-0.011513784,-0.02132686,0.018886574,0.0036984482,0.021415927,-0.015102063,-0.031271935,0.032763638,-0.022634177,-0.015881794,-0.02049077,-0.019111237,-0.0031640676,0.00770166,0.020658508,-0.032719962,0.029949304,0.03812378,0.012831987,0.024678256,-0.027572593,-0.021973675,-0.023571761,-0.030457875,0.011519348,-0.033773094,-0.036179446,0.034908853,-0.02791605,-0.006368483,0.040671747,-0.024147112,-0.003915027,0.0147100575,0.024064293,-0.04237