INSERT INTO document_chunks VALUES (94, 26, 'This chunk analyzes the step response of an overdamped second-order system with a single zero, categorizing the behavior into overshoot, standard response, and inverse response based on the zero''s location. Consider the case of a single zero in an overdamped second-order transfer function $G(s)=\frac{K(\tau_{a}s+1)}{(\tau_{1}s+1)(\tau_{2}s+1)}$. For a step input of magnitude M, the response is $y(t)=KM(1+\frac{\tau_{a}-\tau_{1}}{\tau_{1}-\tau_{2}}e^{-t/\tau_{1}}+\frac{\tau_{a}-\tau_{2}}{\tau_{2}-\tau_{1}}e^{-t/\tau_{2}})$. Zeros do not change the ultimate value $y_{\infty}=KM$ or the number of poles. However, the value of $\tau_{a}$ creates three distinct cases. If $\tau_{a}>\tau_{1}>\tau_{2}$, the system exhibits overshoot. If $0<\tau_{a}\le\tau_{1}$, the response resembles a simple first-order process. If $\tau_{a}<0$, meaning the zero is in the right-half plane, the system exhibits an inverse response.', '[-0.06488577,-0.003372282,-0.018775072,-0.018999532,0.0022823047,-0.016116291,0.003328844,0.03952676,-0.0016100134,0.015661731,-0.019621346,-0.002874869,0.023873115,0.0033841818,0.00089188275,0.0054396708,-0.012192889,0.01817484,-0.018322034,0.015810158,-0.010268499,0.037594367,0.01208199,-0.015255344,-0.018151483,0.012692259,-0.043216005,-0.04332932,-0.016888525,0.018729867,0.007832115,-0.018282231,-0.0014544557,-0.030347275,-0.031573135,0.032846272,0.021015072,-0.031525876,-0.041466553,0.035689622,0.0060428027,-0.02632131,0.017333746,-0.04538667,0.011021725,0.015224346,-0.010600874,-0.045672234,-0.019620597,-0.046992164,-0.027820114,-0.005785295,0.022954008,-0.015525477,-0.00067328004,0.024119122,-0.0052388855,-0.0017050862,-0.064113885,0.012384614,-0.030115433,0.07061241,0.013704061,0.0009864668,0.0012272012,0.04710762,0.002761263,0.0041083638,-0.007266754,-0.018977996,0.034785386,0.04584256,-0.031279325,0.008016481,-0.006980065,0.071390405,0.010995662,-0.004291815,-0.013745889,0.037700344,0.008723757,-0.006681453