INSERT INTO document_chunks VALUES (95, 26, 'This chunk defines Inverse Response and notes that it arises specifically from unstable (right-half plane) zeros. Zeros significantly affect process response characteristics. Stable or left-half plane zeros can cause overshoot even in overdamped processes. Of particular interest are unstable or right-half plane zeros, which give rise to inverse response. Inverse response is characterized by the system initially moving in the opposite direction to where it eventually ends up. This behavior is detrimental for control systems because the controller may be fooled by the initial wrong-way movement (i.e. output moves in opposite direction than intended). Importantly, inverse response will not occur in a standard overdamped second-order transfer function containing two poles but no zero.', '[-0.05249279,-0.0017175395,-0.0448873,0.038826544,-0.016735226,-0.023449149,-0.01169602,0.071664646,-0.0014757866,0.011132094,-0.05598726,0.013351586,-0.0028423076,-0.013131173,-0.010097541,-0.008451662,0.009572234,0.0063414485,-0.026273843,0.0105898585,0.023141716,0.014675758,-0.019837642,-0.03083594,0.007726528,0.0072657727,0.0016784467,-0.0034909172,0.0019920226,0.0330915,0.029993584,-0.020137139,0.0030287625,-0.023048561,-0.020878822,0.022426544,-0.011490217,-0.03593938,-0.0088734515,0.003133409,-0.025400188,-0.009695763,0.041738015,-0.041410208,0.021758378,-0.0033854214,-0.019393563,-0.025811821,-0.03315354,-0.034913436,0.008143777,-0.015445059,0.051019963,-0.024677726,-0.043141194,0.05095691,-0.019577496,-0.0071154116,-0.056317374,0.034360033,-0.008004769,0.03506964,-0.01223224,-0.040067453,-0.031668067,0.041098874,-0.007831166,0.03667095,-0.009847304,-0.028529996,0.007280035,0.055903,-0.0123656625,-0.006788514,-0.019599225,0.04512189,0.0066534504,-0.016067218,-0.014130694,0.019578543,-0.006376818,-0.025479788,-0.011710172,0.029042501,0.025747858,0.037574,-0.020540198,-0.01714453,-0.013296813,-0.0199284,-0.002856558,-0.0060402374,0.0333