INSERT INTO document_chunks VALUES (96, 26, 'This chunk explains the physical origin of inverse response as the result of competing parallel dynamic effects and provides the mathematical condition for its occurrence. Inverse response is the result of two physical effects that act on the process output variable in opposite ways and with different time scales. This can be modeled as two parallel first-order systems with gains $K_1$ and $K_2$ summing to produce the output. Inverse response behavior is observed if the condition $\frac{K_{1}\tau_{2}+K_{2}\tau_{1}}{K_{1}+K_{2}}<0$ is met. This happens when $K_{1}$ and $K_{2}$ have opposite signs and the sign of the overall transfer function gain $K$ is the same as that of the slower process. An industrial application example is a distillation column when the steam pressure to the reboiler is suddenly changed.', '[-0.057383783,0.0336887,-0.055693273,0.021945918,-0.020209506,-0.015971368,-0.029022105,0.051780704,0.034470584,0.03749816,-0.059979875,0.0064725834,-0.018573835,0.020749021,-0.0022826581,0.02453948,0.013833933,0.005761286,-0.018264728,-0.003043195,0.015812488,0.03436215,0.019625792,-0.0215563,0.011578479,0.043723315,-0.013857075,0.0005119539,-0.00079015497,0.02629292,0.009337465,-0.02186894,-0.026621187,-0.023012647,-0.035503287,0.028263178,-0.0062444895,-0.0060885604,-0.027935186,0.031275086,-0.03261137,-0.00066541764,0.040558014,-0.039854188,0.01738942,-0.006820199,-0.026279923,-0.037667215,-0.04245416,-0.05572797,0.01028524,-0.038805123,0.048491407,-0.02846967,-0.018019397,0.0015034211,-0.06402219,0.017273191,-0.052758,0.0013376883,-0.026661005,0.034161925,-0.017099015,-0.018420598,-0.01934175,0.05701497,-0.00073551957,0.025711017,0.0050759926,-0.039452784,-0.012241476,0.04281641,-0.022944322,-0.003965279,-0.032428663,0.031925835,0.013352591,-0.029717928,0.030753033,0.016037166,-0.022291131,-0.0078778975,-0.003903435,0.023752598,-0.017657354,0.041603733,-0.011240909,-0.058339022,-0.055140637,-0.028790336,-0.00