INSERT INTO document_chunks VALUES (97, 27, 'This chunk introduces the physical causes of time delays in chemical processes, such as fluid flow and solid transport, and provides the mathematical definition of a time delay in the time domain. Time delays often occur in processing plants due to phenomena like fluid flow in a pipe or the transport of solid material on a conveyor belt. Mathematically, a time delay $\theta$ between an input $u$ and an output $y$ results in a specific expression where the output is zero for time $t < \theta$ and equals the shifted input $u(t-\theta)$ for time $t \ge \theta$.', '[-0.003975755,0.0015059528,-0.04785956,0.01730197,0.0047229338,-0.01110698,-0.077503145,0.06283382,0.01335353,0.026448358,0.0068828934,0.0023957884,-0.028071608,-0.021573227,-0.0009133742,-0.008873569,0.0059907036,0.052617993,0.00977782,0.013477551,0.006490893,-0.030010356,-0.023461824,-0.018797519,0.021581816,0.022315709,0.010087484,-0.0016151132,0.022648975,0.024039317,0.012705327,0.013212633,-0.011376574,-0.024515813,-0.047711253,-0.021026218,0.012457576,-0.04311394,-0.042949863,0.04806189,-0.01924757,-0.044605445,0.024161886,-0.047151014,0.04478943,0.0054484187,-0.02602254,-0.038146526,-0.00311895,-0.051650587,0.0011942912,-0.05449111,0.07865342,-0.05618457,0.016059577,-0.022002257,-0.063342914,-0.023244519,-0.07931776,0.01794613,-0.0436194,0.0278226,0.016404074,-0.046037696,0.030792078,0.024680197,0.0010160428,-0.007092897,-0.01166566,-0.030735258,0.016004663,0.055379026,0.025537193,-0.024436755,-0.025133858,0.023842992,-0.0061241817,-0.017247865,-0.008634634,0.06747426,-0.0029554476,-0.036417663,-0.0005600457,-0.00622438,0.0101555055,0.00087100227,-0.006804054,-0.0094848145,-0.012560864,-0.011389136,0.04484247,-0.009860083,-0.0009809037,-0.01482896,-0.01636448,-0.0069984146,-0.062578104,0.018179934,0.03917733,0.00656022,0.021793317,0.08077895,-0.0047479705,-0.05714111,0.027594022,-0.0345651,0.038843617,0.010979441,0.033602912,-0.00010262059,0.045745663,0.0361