INSERT INTO document_chunks VALUES (99, 27, 'This chunk details polynomial approximations for time delay transfer functions, specifically the Taylor series expansion and Padé approximations, which are used for analytical solutions and control system design. Since the time delay term $e^{-\theta s}$ is transcendental, it cannot be expressed as a rational function (ratio of two polynomials), which complicates analytical analysis as cannot be factored into poles and zeros. To address this, approximations are used. The simplest is the first-order Taylor series expansion, where $e^{-\theta s} \approx 1 - \theta s$. A more accurate approach is the Padé approximation, which represents the delay as a ratio of polynomials. The first-order Padé approximation is given by $e^{-\theta s} \approx \frac{1 - \theta s/2}{1 + \theta s/2}$. The second-order Padé approximation is more complex, expressed as $e^{-\theta s} \approx \frac{1 - \theta s/2 + \theta^2 s^2/12}{1 + \theta s/2 + \theta^2 s^2/12}$. These approximations allow the time delay to be treated as a rational transfer function.', '[-0.018771758,-0.0021058205,-0.06301045,0.055468403,-0.0056939903,-0.023907846,0.036596894,0.020057235,0.0043604695,0.046686422,-0.0076430677,0.023286628,-0.051226016,0.0035957487,0.022663143,0.028025081,0.040605105,0.004086043,0.0083665475,-0.03195259,-0.0043299966,0.01995089,0.0050200038,0.00516981,-0.046798557,-0.01217122,-0.030735431,-0.0025084862,0.061602,0.027838139,0.012116599,0.03030479,0.0039934083,-0.019315636,-0.038038973,0.04267386,-0.0059959088,-0.045279223,-0.032326333,0.022772724,-0.0358011,-0.049934868,0.010273339,-0.039894607,0.06434636,-0.020380285,-0.018075822,-0.03383686,-0.03422118,-0.02274637,0.010492544,-0.032712992,0.07240446,-0.012191775,0.020928083,0.044931073,-0.0037740895,-0.027085673,-0.08434376,0.0146674635,-0.053086568,0.03140336,-0.01821112,-0.018067816,0.049291655,-0.006793421,0.03309052,0.031224197,0.012411278,0.005002746,-0.002862708,0.03235783,-0.014244405,-0.0