INSERT INTO document_chunks VALUES (101, 28, 'This chunk introduces an alternative first-order approximation for time delays and explains how the relationship can be reversed to approximate small time constants as time delays. An alternative first-order approximation for the time delay transfer function is given by $e^{-\theta_{0}s} = \frac{1}{e^{\theta_{0}s}} \approx \frac{1}{1+\theta_{0}s}$ (Equation 5-58), where the time constant has a value of $\theta$. These expressions can be used to approximate a pole or zero term in a transfer function. Furthermore, this approximation can be reversed: the right-hand side (a small lag or pole) can be approximated as the left-hand side so as to approximate non-dominant (much smaller than rest) time constant with delay.', '[-0.016755177,0.0045014992,-0.023535416,0.04153542,-0.0026958983,-0.016681377,0.02249415,0.053607855,0.02626002,0.014806883,-0.02726513,0.009411392,-0.022824183,0.006437566,0.008390096,0.0155318165,-0.0008325855,-0.0008419235,0.0034516428,0.008627893,0.0072044213,0.021765355,-0.018934967,0.03189166,-0.002386928,-0.013571078,-0.024890676,-0.006468511,0.033953063,0.03579122,0.023496179,0.023787087,0.027592367,-0.051787276,-0.043674156,0.03271108,0.0119399745,-0.035077527,-0.03151607,0.054382946,-0.009342063,-0.03248986,0.025831174,-0.0098735625,0.047617435,0.0076644854,-0.0011068591,-0.024774676,-0.039430678,-0.078256,0.007003889,-0.040469818,0.07693567,0.0007746325,0.012646136,0.04650121,0.007142181,-0.042653944,-0.05727158,0.037063252,-0.0283644,0.0083305985,-0.010164225,-0.019404814,0.027522068,0.008084509,-0.0067466986,0.022674292,-0.0029892444,-0.012547748,-0.009611501,0.06362886,-0.031206416,-0.034722302,-0.023457415,0.036074065,0.024981515,0.050444473,0.021581845,0.024991961,0.006568769,-0.013759466,0.013450138,-0.0060599204,-0.0072491174,0.05078915,0.018318169,0.045281906,-0.019666858,-0.035284597,0.003772055,0.00018671073,0.019446198,-0.032606304,-0.009717667,-0.03816334,-0.03551526,0.043756332,0.06966