INSERT INTO document_chunks VALUES (102, 28, 'This chunk details Skogestad''s "Half Rule," a systematic method for reducing the order of a transfer function by appropriately distributing the largest neglected time constant into the effective delay and the smallest retained time constant. Skogestad''s half rule provides a robust method for approximating higher-order systems into a lower-order model (typically First-Order Plus Time Delay) by handling the largest neglected time constant in a specific manner. According to this rule, one half of the value of the largest neglected time constant is added to the existing time delay (if any), while the other half is added to the smallest retained time constant. Any time constants that are smaller than the "largest neglected time constant" are simply approximated entirely as part of the effective time delay using the relationship $e^{-\theta_{0}s}\approx1-\theta_{0}s$.', '[-0.04104059,0.000999823,-0.033489093,0.012241436,-0.015031229,-0.039595865,0.037841942,0.028419381,-0.009031948,0.046372,-0.034695726,0.019292941,-0.024173517,0.015340017,0.015011477,0.02509378,0.093523234,-0.012961813,-0.02470814,-0.002768126,0.0017924557,-0.024645576,0.014401399,0.01591994,0.008797262,0.0066201934,-0.016685303,-0.001100113,0.03196595,0.06357617,0.047150552,0.034558386,0.012887848,-0.036798406,-0.033965036,0.031472065,0.014626591,-0.0653493,-0.02426695,0.033569723,-0.023963729,-0.052080147,-0.0013396437,-0.04877029,0.061953217,0.008144589,-0.007603071,-0.049198885,-0.017654367,-0.016014103,-0.006332374,-0.0314324,0.015320881,-0.02905713,0.044155583,0.04725677,-0.015580084,-0.032209564,-0.04948221,0.024249356,-0.050789073,0.028108852,-0.0180905,0.010747755,0.040047787,0.021753289,0.01896441,0.03851759,-0.014900835,-0.021481544,-0.0014453739,0.05316701,-0.022655303,-0.0450342,-0.03492581,0.028098222,-0.011565568,0.021610305,0.0072763306,0.04658314,0.0233802,-0.00654212,0.05007825,-0.03397938,-0.024464639,0.033618566,0.022343697,0.03835821,-0