INSERT INTO document_chunks VALUES (103, 28, 'This chunk presents a problem example to derive an approximate first-order-plus-time-delay (FOPTD) model for a specific third-order transfer function with a zero. Example 3 challenges the student to derive an approximate first-order-plus-time-delay model for the specific transfer function $G(s)=\frac{K(-0.1s+1)}{(5s+1)(3s+1)(0.5s+1)}$. The problem requires applying two distinct approximation methods to compare their effectiveness: first, using the Taylor''s series expansion directly, and second, applying Skogestad''s half rule. This example serves to demonstrate how the rules for handling numerator dynamics (the zero at -0.1s) and distributing the time constants (5, 3, and 0.5) are applied in practice.', '[-0.03504705,-0.025706481,-0.03340799,0.0106106335,0.0025487603,-0.0040851673,0.019312957,-0.0016546567,-0.0024903968,0.020886486,-0.046121195,0.01503076,-0.032687064,0.0037527704,0.035124477,0.039239097,0.05122721,-0.023310728,0.005541377,-0.020095529,0.0077043003,0.006323787,0.0032898434,0.016800003,-0.016761892,0.011582822,-0.014105173,-0.0077182166,0.018835487,0.049112774,0.048269372,0.010941551,-0.021748452,-0.037147652,-0.059807837,0.03951485,0.024459055,-0.0132483905,-0.04943994,0.021949558,-0.026241561,-0.023986632,-0.0011780326,-0.032104954,-4.7049427e-05,-0.0049553756,-0.018657928,-0.029072793,-0.028640643,-0.023417907,-0.0005032355,-0.02933099,0.012599895,-0.039680056,0.038202416,0.041237064,-0.03447762,-0.056448627,-0.04011741,0.022607544,-0.053927224,0.06920299,0.00020791625,-0.006423428,0.012288671,0.01230145,-0.0011743514,-0.006868485,0.004699258,-0.0099131595,-0.007737814,0.014622873,-0.015728187,-0.013703931,-0.058384623,-0.006569906,-0.02021893,0.03835833,0.013643704,0.036374222,0.020629223,0.02629035,0.05322875,-0.028924672,-0.034454733,0.03182128,0.031791907,0.048014153,0.01067646,-0.040300183,-0.0011522792,-0.007979844,0.008481423,-0.04525895,-0.01922137,-0.0037678084,-0.033725277,0.03890397,0.05788