INSERT INTO document_chunks VALUES (105, 29, 'This chunk defines interacting and non-interacting processes, illustrating the concept with a reactor-distillation example and providing the transfer function for a non-interacting tank system. A process is said to be interacting if changes in a downstream unit affect upstream units, and vice versa; otherwise, the process is classified as non-interacting. A common example of a non-interacting system is when the exit stream from a reactor serves as the feed to a distillation column, as the column does not influence the reactor. For a non-interacting system of two tanks in series, the overall transfer function relating the second tank''s level $H_2(s)$ to the inlet flow $Q_i(s)$ is the product of the individual transfer functions, given by $\frac{H_{2}(s)}{Q_{i}(s)}=\frac{R_{2}}{(A_{1}R_{1}s+1)(A_{2}R_{2}s+1)}$.', '[-0.031842865,-0.028196763,-0.019240629,0.05527959,-0.008092682,-0.05390659,-0.017249264,0.038073238,-0.014847312,0.027759906,0.0021133584,-0.049024686,-0.016451614,0.043003634,0.0415633,0.011278234,-0.013201107,0.0018777193,0.015233286,0.0057472917,-0.023740938,-0.007978656,0.0030393493,-0.011773427,0.0020344837,0.010555972,-0.024197046,-0.030707493,0.009088707,0.018865544,0.054923795,-0.0060359337,-0.062523074,-0.033630963,-0.0033229457,0.010800736,-0.008589766,-0.030223979,-0.029834813,0.05332241,-0.008159396,-0.022506695,0.021879258,-0.05923851,0.029815521,0.00079323456,-0.020753205,-0.04478908,-0.049062617,-0.04878647,-0.05218479,-0.014760898,0.05131055,-0.050219275,-0.043442212,0.0062779,-0.053801134,-0.015504035,-0.07000116,0.039637536,-0.011183249,0.029523626,0.027759679,-0.026940264,-0.0033421498,0.032061804,0.006762251,0.01835659,-0.009890602,-0.063379556,0.01966412,0.022066068,-0.019964905,-0.029905085,-0.034732886,0.058329836,0.040676214,-0.031839557,0.036041334,0.028638212,0.005344273,-0.04431616,-0.00031458735,0.008490457,-0.021513674,0.010291791,0.0055704927,0.005039705,0.03361817,-0.04372431,-0.0