INSERT INTO document_chunks VALUES (106, 29, 'This chunk presents the setup for interacting processes using a two-tank liquid level system where the flow between tanks depends on the level difference. In an interacting process configuration, the dynamics are coupled. For a system of two tanks where the flow $q_1$ from the first tank to the second depends on the head difference $h_1 - h_2$, the behavior is distinct from the non-interacting case. The problem posed for this configuration is to determine the overall transfer function $G(s)=\frac{H_{2}(s)}{Q_{i}(s)}$ which accounts for this interaction.', '[-0.040512767,-0.04800969,-0.01786319,0.041789945,-0.021622779,-0.03994324,0.0028826566,0.01991782,-0.009496258,0.0149899535,-0.012500555,-0.06603495,-0.0030943973,0.039807014,0.00758405,0.02275425,0.0059226872,0.01065987,-0.008582982,-0.008320894,-0.0064422092,-0.021415593,0.011537321,0.011517235,-0.0016846939,0.029057795,-0.024866385,-0.0231364,0.021710385,0.029353552,0.031208528,-0.017375914,-0.04614702,-0.03989143,0.01244125,-0.03823389,-0.015144512,-0.025119947,-0.037296537,0.033975843,0.008689742,-0.038169,0.02719262,-0.035420615,0.0053910506,-4.5169472e-05,-0.040421136,-0.0457253,-0.0537492,-0.019247465,-0.049996767,-0.05108053,0.02697735,-0.044891838,-0.014537581,0.024556778,-0.04597041,-0.014267188,-0.04168138,0.027683305,-0.042307682,0.05528664,0.039903536,-0.012779614,0.011762586,0.05270212,0.0010436882,0.032546204,-0.015398246,-0.053475894,-0.010105895,0.0056755166,0.022542225,-0.004075018,-0.029401211,0.059544414,0.04030285,-0.05853824,0.03680129,0.013524562,-0.012964754,-0.0481954,0.0040199696,0.019880598,-0.008373658,0.018306669,0.012181726,-0.007413432,0.036315635,-0.050598644,-0.032672435,-0.023803849,0.01194805,-0.03337787,-0.027310487,0.013887646,-0.028327765,0.03659556,0.013633702,-0.017692849,0.022098852,0.031207932,-0.019766951,-0.059376847,0.03308072,0.012792029,0.082952216,0.042038042,-0.0022999474,-0.018221365,0.026444066,0.007297637,0.00482195